class TargetData {
    constructor(data) {
        this.baseConstructor(data);
    }

    baseConstructor(data) {
        this.createEmpty();
        if (data != undefined) {
            let dataType = data.type;
            if (dataType == undefined) {
                dataType = data.get("_type");
            }
            if (dataType != undefined) {
                if (dataType == "api") {
                    this.importMessage(data);
                }
                if (dataType == "graphic") {
                    this.importTokenData(data);
                }
            } else if (data.charId != undefined) {
                this.importJSON(data);
            }
        }
    }

    createEmpty() {
        this.charId = "";
        this.charName = "";
        this.tokenId = "";
        this.displayName = "";
        this.owner = "";
        this.teamIndex = 0;
    }

    importJSON(json) {
        this.charId = json.charId;
        this.charName = json.charName;
        this.tokenId = json.tokenId;
        this.displayName = json.displayName;
        this.owner = json.owner;
        this.teamIndex = json.teamIndex;
    }

    importMessage(msg) {
        if (msg.selected && msg.selected.length > 0) {
            this.importTokenData(TokenReference.GetToken(msg.selected[0]._id));
        }
    }

    importTokenData(token) {
        if (token == undefined) {
            Debug.LogError(`[TargetData] No token exists.`);
            return;
        }

        this.charId = token.get('represents');
        if (this.charId == undefined || this.charId == "") {
            Debug.LogError(`[TargetData] (${token.name}) has no representative character.`);
            return;
        }
        this.tokenId = token.get("_id");
        this.displayName = token.get("name");

        let character = getObj('character', this.charId);
        this.charName = character.get("name");
        this.setOwner(character);
        this.setCharacterData();
    }

    findCharacterByName(characterName) {
        let characters = findObjs({
            _type: 'character',
            name: characterName
        }, {caseInsensitive: true});
        if (characters.length > 0) {
            return characters[0];
        }

        characters = findObjs({_type: 'character'});
        characters.forEach(function (chr) {
            if (chr.get('name') == characterName) {
                return chr;
            }
        });
        return undefined;
    }

    importCharacterByName(characterName) {
        let character = this.findCharacterByName(characterName);
        if (character == undefined) {
            Debug.LogError(`[importCharacterByName] Error. Character ${characterName} could not be found.`);
            return;
        }

        this.charId = character.get("_id");
        this.charName = character.get("name");
        this.setOwner(character);
        this.setCharacterData();
    }

    setOwner(character) {
        let ownerId = character.get("controlledby").split(",")[0];
        if (ownerId != "") {
            this.owner = getObj("player", ownerId).get("_displayname");
        }
    }

    setCharacterData() {
        let attributeHandler = new SandboxAttributeHandler(this.charId);
        let targetData = this;
        let displayNameVar = WuxDef.GetVariable("DisplayName");
        let fullNameVar = WuxDef.GetVariable("FullName");
        let teamIndexVar = WuxDef.GetVariable("TeamIndex");
        attributeHandler.addMod([displayNameVar, fullNameVar, teamIndexVar]);
        attributeHandler.addFinishCallback(function (attrHandler) {
            if (attrHandler.parseString(fullNameVar) != "GenericOverride") {
                targetData.displayName = attrHandler.parseString(displayNameVar);
            }
        });
        attributeHandler.run();
    }
}

class TokenTargetData extends TargetData {
    constructor(token, targetData) {
        super(undefined);
        if (token == undefined) {
            return;
        }

        if (targetData != undefined) {
            this.importJSON(targetData);
            this.token = token;
        } else {
            this.baseConstructor(token);
        }
    }

    createEmpty() {
        super.createEmpty();
        this.token = undefined;
        this.combatDetails = undefined;
    }

    importTokenData(token) {
        this.token = token;
        super.importTokenData(token);
    }

    importTokenDataOnPlayerPage() {
        let tokens = findObjs({
            _pageid: Campaign().get("playerpageid"),
            _type: "graphic",
            represents: this.charId
        });
        if (tokens.length == 0) {
            return;
        }
        this.token = tokens[0];
        this.tokenId = this.token.get("_id");
    }

    isCharacter() {
        return this.isBarLinked(1);
    }
    validateToken() {
        if (this.token == undefined) {
            Debug.LogError(`[TokenTargetData] No token data exists for ${this.charName}`);
            return false;
        }
        return true;
    }

    // token bar
    initToken() {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set("bar_location", "overlap_bottom");
        return true;
    }

    setBar(barIndex, variableObj, showBar, showText) {
        if (!this.validateToken()) {
            return false;
        }
        if (variableObj == undefined) {
            this.token.set(`bar${barIndex}_link`, "");
            this.token.set(`bar${barIndex}_value`, "");
            this.token.set(`bar${barIndex}_max`, "");
        } else {
            this.token.set(`bar${barIndex}_link`, variableObj.get("_id"));
            this.token.set(`bar${barIndex}_value`, variableObj.get("current"));
            this.token.set(`bar${barIndex}_max`, variableObj.get("max"));
        }
        this.token.set(`showplayers_bar${barIndex}`, showBar);
        this.token.set(`showplayers_bar${barIndex}text`, showText ? "2" : "0");
    }

    unlinkBar(barIndex) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set(`bar${barIndex}_link`, "");
    }

    isBarLinked(barIndex) {
        if (!this.validateToken()) {
            return false;
        }
        let barLink = this.token.get(`bar${barIndex}_link`);
        return barLink != undefined && barLink != "";
    }

    getBarValue(barIndex) {
        if (!this.validateToken()) {
            return 0;
        }
        let value = this.token.get(`bar${barIndex}_value`);
        if (value == "" || value == undefined) {
            return 0;
        }
        
        return value;
    }
    getBarMax(barIndex) {
        if (!this.validateToken()) {
            return 0;
        }
        let value = this.token.get(`bar${barIndex}_max`);
        if (value == "" || value == undefined) {
            return 0;
        }

        return value;
    }
    setBarValue(barIndex, value) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set(`bar${barIndex}_value`, value);
    }

    // nameplate
    showTokenName(isShown) {
        if (!this.validateToken()) {
            return false;
        }
        if (isShown) {
            this.token.set("name", this.displayName);
            this.token.set("showname", true);
            this.token.set("showplayers_name", true);
        } else {
            this.token.set("showname", false);
        }
    }

    // tooltip
    showTooltip(isShown) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set("show_tooltip", isShown);
        if (!isShown) {
            this.setTooltip("");
        }
    }

    setTooltip(value) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set("tooltip", value);
    }

    getTokenNote() {
        if (!this.validateToken()) {
            return false;
        }
        return this.token.get("gmnotes");
    }
    setTokenNote(value) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set("gmnotes", value);
    }

    // icon settings
    setEnergyIcon(value) {
        this.setIcon("status_yellow", value);
    }
    setTurnIcon(value) {
        this.setIcon("status_pink", value);
    }
    setAdvantageIcon(value) {
        this.setIcon("status_purple", value);
    }
    getAdvantageIcon() {
        return this.getIcon("status_purple");
    }

    getIcon(iconName) {
        if (!this.validateToken()) {
            return false;
        }
        let value = this.token.get(iconName);
        if (value == undefined || value == "") {
            return 0;
        }
        return value;
    }
    setIcon(iconName, value) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set(iconName, value);
    }

    getDowned() {
        if (!this.validateToken()) {
            return false;
        }
        return this.token.get("status_dead");
    }
    setDowned(value, attributeHandler) {
        if (!this.validateToken()) {
            return false;
        }
        this.token.set("status_dead", value);

        let subAttributeHandler = new SandboxAttributeHandler(attributeHandler.characterId);
        if (value == true) {
            this.addStatus(subAttributeHandler, "Stat_Downed", 1);
            this.addStatus(subAttributeHandler, "Stat_Dazed", 1);
        }
        else {
            this.removeStatus(subAttributeHandler, "Stat_Downed");
        }
        subAttributeHandler.run();
    }

    // Modifiers
    setDisplayName() {
        let attributeHandler = new SandboxAttributeHandler(this.charId);
        let tokenData = this;
        let displayNameVar = WuxDef.GetVariable("DisplayName");
        let fullNameVar = WuxDef.GetVariable("FullName");
        attributeHandler.addMod(displayNameVar);
        attributeHandler.addFinishCallback(function (attrHandler) {
            if (attrHandler.parseString(fullNameVar) != "GenericOverride") {
                tokenData.displayName = attrHandler.parseString(displayNameVar);
            }
        });
        attributeHandler.run();
    }

    addMod(modDefinitionName, attributeHandler, value, finishCallback) {
        finishCallback = finishCallback == undefined ? function (results, attrHandler, attributeVar) {
            attrHandler.addUpdate(attributeVar, results.newValue, false);
        } : finishCallback;
        
        this.modifyResourceAttribute(attributeHandler,
            modDefinitionName,
            value,
            this.addModifierToAttribute,
            finishCallback
        );
    }
    addModNoCap(modDefinitionName, attributeHandler, value) {
        this.modifyResourceAttribute(attributeHandler,
            modDefinitionName,
            value,
            this.addModifierToAttributeNoCap,
            function (results, attrHandler, attributeVar) {
                attrHandler.addUpdate(attributeVar, results.newValue, false);
            }
        );
    }
    getAdvantage() {
        let value = this.getAdvantageIcon();
        if (value == undefined || value == "" || value == false) {
            return 0;
        }
        value = parseInt(value);
        if (isNaN(value)) {
            return 0;
        }
        return value;
    }

    // Combat Details
    getCombatDetails(attributeHandler) {
        this.refreshCombatDetails(attributeHandler);
        return this.combatDetails;
    }
    refreshCombatDetails(attributeHandler, tokenNoteReference) {
        if (attributeHandler == undefined) {
            return;
        }
        this.combatDetails = new CombatDetailsHandler(attributeHandler);
        this.combatDetails.setData(attributeHandler);
        if (tokenNoteReference == undefined) {
            tokenNoteReference = new TokenNoteReference(this.getTokenNote());
        }
        this.combatDetails.setDataFromTokenNote(tokenNoteReference);
    }
    setCombatDetails(attrHandler, tokenNoteReference, statusHandler) {
        if (this.combatDetails == undefined) {
            Debug.LogError(`[TokenTargetData] No combat details exist for ${this.charName}`);
            return;
        }

        this.combatDetails.setData(attrHandler);

        if (this.combatDetails.hasDisplayStyle()) {
            if (tokenNoteReference == undefined) {
                tokenNoteReference = new TokenNoteReference(this.getTokenNote());
            }
            this.combatDetails.setDataFromTokenNote(tokenNoteReference);
            let toolTip = this.combatDetails.printTooltip(attrHandler, this.displayName);
            if (statusHandler == undefined) {
                statusHandler = tokenNoteReference.statusHandler;
            }
            toolTip += statusHandler.printStatusSummary();
            this.setTooltip(toolTip);
            this.showTooltip(true);
        } else {
            this.setTooltip("");
            this.showTooltip(false);
        }
    }

    // Note Reference
    importTokenNoteReferenceData(attributeHandler) {
        let tokenTargetData = this;
        let surgeDef = WuxDef.GetVariable("Surge");
        let vitalityDef = WuxDef.GetVariable("Cmb_Vitality");
        attributeHandler.addAttribute(surgeDef, vitalityDef);

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            let tokenNoteRef = new TokenNoteReference(tokenTargetData.getTokenNote());
            tokenNoteRef.surges.current = attrHandler.parseInt(surgeDef, 0, true);
            tokenNoteRef.surges.max = tokenNoteRef.surges.current;
            tokenNoteRef.vitality.current = attrHandler.parseInt(vitalityDef, 0, true);
            tokenNoteRef.vitality.max = tokenNoteRef.vitality.current;
            Debug.Log(`Importing token note reference data for ${tokenTargetData.displayName} with values ${tokenNoteRef.surges.current}/${tokenNoteRef.surges.max} and ${tokenNoteRef.vitality.current}/${tokenNoteRef.vitality.max}`);
            tokenTargetData.setTokenNote(JSON.stringify(tokenNoteRef));
        });
    }
    
    getTeamIndex(tokenNoteReference) {
        if (tokenNoteReference == undefined) {
            tokenNoteReference = new TokenNoteReference(this.getTokenNote());
        }
        
        return tokenNoteReference.teamIndex;
    }
    setTeamIndex(index, tokenNoteReference) {
        if (tokenNoteReference == undefined) {
            tokenNoteReference = new TokenNoteReference(this.getTokenNote());
        }
        Debug.LogError(`Setting team index to ${index}`);
        tokenNoteReference.teamIndex = index;
        this.setTokenNote(JSON.stringify(tokenNoteReference));
    }

    // Social Modifiers
    addImpatience(attributeHandler, value, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToImpatience : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 1, value,
            this.addModifierToAttribute, resultsCallback);
    }

    emptyImpatience(attributeHandler, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToImpatience : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 1, 0,
            this.setModifierToAttribute, resultsCallback);
    }

    applyResultsToImpatience(results, attrHandler, attributeVar, tokenTargetData) {
        if (state.WuxConflictManager.conflictType == "Social") {
            tokenTargetData.setBarValue(1, results.newValue);
        }
        return results;
    }

    getFavor() {
        if (state.WuxConflictManager.conflictType == "Social") {
            return this.getBarValue(3);
        }
        return 0;
    }
    getMaxFavor() {
        if (state.WuxConflictManager.conflictType == "Social") {
            return this.getBarMax(3);
        }
        return 0;
    }
    
    setMaxFavor(attributeHandler, value) {
        Debug.Log(`Setting Bar 3 to ${value}`);
        this.token.set(`bar3_max`, value);
    }
    
    addFavor(attributeHandler, value, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToFavor : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 3, value,
            this.addModifierToAttributeNoCap, resultsCallback);
    }

    emptyFavor(attributeHandler, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToFavor : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 3, 0,
            this.setModifierToAttribute, resultsCallback);
    }

    applyResultsToFavor(results, attrHandler, attributeVar, tokenTargetData) {
        if (state.WuxConflictManager.conflictType == "Social") {
            tokenTargetData.setBarValue(3, results.newValue);
        }
        return results;
    }

    // HP
    addHp(attributeHandler, value, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToHp : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 1, value,
            this.addModifierToAttribute, resultsCallback);
    }

    setHpToFull(attributeHandler, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToHp : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 1, "max",
            this.setModifierToAttribute, resultsCallback);
    }

    applyResultsToHp(results, attrHandler, attributeVar, tokenTargetData) {
        if (state.WuxConflictManager.conflictType == "Battle") {
            tokenTargetData.setBarValue(1, results.newValue);
        }
        return results;
    }

    // Will
    addWill(attributeHandler, value, resultsCallback, modifyCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToWill : resultsCallback;
        modifyCallback = modifyCallback == undefined ? this.addModifierToAttribute : modifyCallback;
        this.modifyBarAttribute(attributeHandler, 2, value,
            modifyCallback, resultsCallback);
    }

    setWillToFull(attributeHandler, resultsCallback) {
        resultsCallback = resultsCallback == undefined ? this.applyResultsToWill : resultsCallback;
        this.modifyBarAttribute(attributeHandler, 2, "max",
            this.setModifierToAttribute, resultsCallback);
    }

    applyResultsToWill(results, attrHandler, attributeVar, tokenTargetData) {
        tokenTargetData.setBarValue(2, results.newValue);
        return results;
    }

    // Energy
    addEnergy(attributeHandler, value, resultsCallback) {
        if (value == undefined) {
            return;
        }
        resultsCallback = resultsCallback == undefined ? this.applyResultsToEnergy : resultsCallback;

        this.modifyIconAttribute(attributeHandler, "status_yellow", value,
            function (results, value, attributeHandler, tokenTargetData) {
                results.max = 9;
                return tokenTargetData.addModifierToAttribute(results, value, attributeHandler, tokenTargetData);
            }, resultsCallback);
    }

    setEnergyToStart(attributeHandler, resultsCallback) {
        let startEnVar = WuxDef.GetVariable("StartEN");
        attributeHandler.addMod(startEnVar);
        resultsCallback = resultsCallback == undefined ? this.applyResultsToEnergy : resultsCallback;

        this.modifyIconAttribute(attributeHandler, "status_yellow", startEnVar,
            function (results, value, attributeHandler, tokenTargetData) {
                results.max = 9;
                return tokenTargetData.setModifierToAttribute(results, value, attributeHandler);
            }, resultsCallback);
    }

    addStartRoundEnergy(attributeHandler, resultsCallback) {
        let roundEnVar = WuxDef.GetVariable("RoundEN");
        attributeHandler.addMod(roundEnVar);
        resultsCallback = resultsCallback == undefined ? this.applyResultsToEnergy : resultsCallback;
        
        this.modifyIconAttribute(attributeHandler, "status_yellow", roundEnVar,
            function (results, value, attributeHandler, tokenTargetData) {
                results.max = 9;
                return tokenTargetData.addModifierToAttribute(results, value, attributeHandler, tokenTargetData);
            }, resultsCallback);
    }

    applyResultsToEnergy(results, attrHandler, attributeVar, tokenTargetData) {
        if (tokenTargetData.isBarLinked(1)) {
            attrHandler.addUpdate(attributeVar, results.newValue, false);
        }
        tokenTargetData.setEnergyIcon(results.newValue);
        return results;
    }

    // Move Charge
    addMoveCharge(attributeHandler, value, resultsCallback) {
        let tokenTargetData = this
        value = parseInt(value);
        resultsCallback = resultsCallback == undefined ? tokenTargetData.applyResultsMoveCharge : resultsCallback;

        if (tokenTargetData.isBarLinked(1)) {
            this.modifyResourceAttribute(attributeHandler, "MvCharge", value,
                tokenTargetData.addModifierToAttributeNoCap, resultsCallback);
        } else {
            this.modifyIconAttribute(attributeHandler, "status_pink", value,
                tokenTargetData.addModifierToAttributeNoCap, resultsCallback);
        }
    }
    setMoveCharge(attributeHandler, value, resultsCallback) {
        let tokenTargetData = this
        value = parseInt(value);
        resultsCallback = resultsCallback == undefined ? tokenTargetData.applyResultsMoveCharge : resultsCallback;

        if (tokenTargetData.isBarLinked(1)) {
            this.modifyResourceAttribute(attributeHandler, "MvCharge", value,
                tokenTargetData.setModifierToAttribute, resultsCallback);
        } else {
            this.modifyIconAttribute(attributeHandler, "status_pink", value,
                tokenTargetData.setModifierToAttribute, resultsCallback);
        }
    }
    addRun(attributeHandler, resultsCallback) {
        this.addDashModifiers(attributeHandler);
        resultsCallback = resultsCallback == undefined ? this.applyResultsMoveCharge : resultsCallback;

        if (this.isCharacter()) {
            this.modifyResourceAttribute(attributeHandler, "MvCharge", 0,
                function (results, value, attrHandler, tokenTargetData) {
                    results.newValue = tokenTargetData.performRun(attrHandler);
                },
                resultsCallback);
        } else {
            this.modifyIconAttribute(attributeHandler, "status_pink", 0,
                function (results, value, attrHandler, tokenTargetData) {
                    results.newValue = tokenTargetData.performRun(attrHandler);
                },
                resultsCallback);
        }
    }

    addDash(attributeHandler, resultsCallback) {
        this.addDashModifiers(attributeHandler);
        resultsCallback = resultsCallback == undefined ? this.applyResultsMoveCharge : resultsCallback;

        if (this.isCharacter()) {
            this.modifyResourceAttribute(attributeHandler, "MvCharge", 0,
                function (results, value, attrHandler, tokenTargetData) {
                    results.newValue = results.current + tokenTargetData.performDash(attrHandler);
                },
                resultsCallback);
        } else {
            this.modifyIconAttribute(attributeHandler, "status_pink", 0,
                function (results, value, attrHandler, tokenTargetData) {
                    results.newValue = results.current + tokenTargetData.performDash(attrHandler);
                },
                resultsCallback);
        }
    }
    addDashModifiers(attributeHandler) {
        attributeHandler.addMod([WuxDef.GetVariable("Cmb_Mv"), WuxDef.GetVariable("Cmb_MvDash")]);
    }
    performRun(attrHandler) {
        let speed = attrHandler.parseInt(WuxDef.GetVariable("Cmb_Mv"), 0, false);
        let chilled = this.getStatusRank(attrHandler, "Stat_Chilled");
        if (chilled > 0) {
            speed -= chilled;
        }
        let vined = this.getStatusRank(attrHandler, "Stat_Vined");
        if (vined > 0) {
            speed -= vined;
        }
        return Math.max(speed, 1);
    }
    performDash(attrHandler) {
        let speed = attrHandler.parseInt(WuxDef.GetVariable("Cmb_MvDash"), 0, false);
        let earthblight = this.getStatusRank(attrHandler, "Stat_Earthblight");
        if (earthblight > 0) {
            speed -= earthblight * 2;
        }
        return Math.max(speed, 1);
    }
    applyResultsMoveCharge(results, attrHandler, attributeVar, tokenTargetData) {
        if (tokenTargetData.isBarLinked(1)) {
            attrHandler.addUpdate(attributeVar, results.newValue, false);
        }
        tokenTargetData.setTurnIcon(results.newValue);
        return results;
    }

    // Surge
    addSurge(attributeHandler, value, resultsCallback) {
        let tokenTargetData = this
        value = parseInt(value);
        resultsCallback = resultsCallback == undefined ? tokenTargetData.applyResultsSurge : resultsCallback;
        tokenTargetData.refreshCombatDetails(attributeHandler);

        if (tokenTargetData.isBarLinked(1)) {
            this.modifyResourceAttribute(attributeHandler, "Surge", value,
                tokenTargetData.addModifierToAttribute, resultsCallback);
        } else {
            this.modifyNoteAttribute(attributeHandler, "surges", value,
                tokenTargetData.addModifierToAttribute, resultsCallback);
        }
    }
    applyResultsSurge(results, attrHandler, attributeVar, tokenTargetData) {
        if (tokenTargetData.isCharacter()) {
            attrHandler.addUpdate(attributeVar, results.newValue, false);
            tokenTargetData.combatDetails.onUpdateSurges(attrHandler, results.newValue);
            tokenTargetData.setCombatDetails(attrHandler);
        }
        let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
        tokenNoteReference.surges.current = results.newValue;
        tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
        tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
    }

    // Vitality
    addVitality(attributeHandler, value, resultsCallback) {
        let tokenTargetData = this
        value = parseInt(value);
        resultsCallback = resultsCallback == undefined ? tokenTargetData.applyResultsVitality : resultsCallback;
        tokenTargetData.refreshCombatDetails(attributeHandler);

        if (tokenTargetData.isCharacter()) {
            this.modifyResourceAttribute(attributeHandler, "Cmb_Vitality", value,
                tokenTargetData.addModifierToAttribute, resultsCallback);
        } else {
            this.modifyNoteAttribute(attributeHandler, "vitality", value,
                tokenTargetData.addModifierToAttribute, resultsCallback);
        }
    }
    applyResultsVitality(results, attrHandler, attributeVar, tokenTargetData) {
        if (tokenTargetData.isCharacter()) {
            attrHandler.addUpdate(attributeVar, results.newValue, false);
            tokenTargetData.combatDetails.onUpdateVitality(attrHandler, results.newValue);
            tokenTargetData.setCombatDetails(attrHandler);
        }
        let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
        tokenNoteReference.vitality.current = results.newValue;
        tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
        tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);

        return results;
    }

    // Status
    hasStatus(attrHandler, statusDefinitionName) {
        let tokenTargetData = this;
        let tokenNote = tokenTargetData.getTokenNote();
        if (!tokenNote) {
            return false;
        }
        let tokenNoteReference = new TokenNoteReference(tokenNote);
        return tokenNoteReference.statusHandler.hasStatus(statusDefinitionName);
    }
    getStatusRank(attrHandler, statusDefinitionName) {
        let value = this.hasStatus(attrHandler, statusDefinitionName);
        if (!value) {
            return 0;
        }
        return value;
    }
    setStatus(attributeHandler, statusDefinitionName, rank) {
        this.modifyStatus(attributeHandler, statusDefinitionName, "set", rank);
    }

    showAddStatusList(statusType) {
        let statusObject = new StatusHandler();
        return statusObject.printAddStatusPage(this, statusType);
    }
    
    addStatus(attributeHandler, statusDefinitionName, rank) {
        this.modifyStatus(attributeHandler, statusDefinitionName, "add", rank);
    }

    removeStatus(attributeHandler, statusDefinitionName) {
        this.modifyStatus(attributeHandler, statusDefinitionName, "remove");
    }
    
    removeAllStatus(attributeHandler) {
        let tokenTargetData = this;
        tokenTargetData.refreshCombatDetails(attributeHandler);

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
            tokenNoteReference.statusHandler.removeAllStatus();
            tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
            tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
        });
    }

    modifyStatus(attributeHandler, statusDefinitionName, task, rank) {
        let tokenTargetData = this;
        tokenTargetData.refreshCombatDetails(attributeHandler);

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
            switch (task) {
                case "set":
                    tokenNoteReference.statusHandler.setStatus(statusDefinitionName, rank);
                    break;
                case "add":
                    tokenNoteReference.statusHandler.addStatus(statusDefinitionName, rank);
                    break;
                case "remove":
                    tokenNoteReference.statusHandler.removeStatus(statusDefinitionName);
                    break;
            }
            tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
            tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
        });
    }

    getModifyResults(name) {
        return {
            name: name,
            current: 0,
            max: 0,
            newValue: 0,
            remainder: 0
        };
    }

    modifyBarAttribute(attributeHandler, barIndex, value, modCallback, finishCallback) {
        let currentValue = this.token.get(`bar${barIndex}_value`);
        if (currentValue === "" || currentValue === undefined) {
            return;
        }
        
        let tokenTargetData = this;
        let results = tokenTargetData.getModifyResults(barIndex);

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            results.current = parseInt(tokenTargetData.token.get(`bar${barIndex}_value`));
            results.max = parseInt(tokenTargetData.token.get(`bar${barIndex}_max`));
            modCallback(results, value, attrHandler, tokenTargetData);
            finishCallback(results, attrHandler, "", tokenTargetData);
        });
    }

    modifyIconAttribute(attributeHandler, iconName, value, modCallback, finishCallback) {
        let tokenTargetData = this;
        let results = tokenTargetData.getModifyResults(iconName);

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            results.current = parseInt(tokenTargetData.getIcon(iconName));
            if (isNaN(results.current)) {
                results.current = 0;
            }
            results.max = 99;
            modCallback(results, value, attrHandler, tokenTargetData);
            finishCallback(results, attrHandler, "", tokenTargetData);
        });
    }

    modifyNoteAttribute(attributeHandler, attrName, value, modCallback, finishCallback) {
        let tokenTargetData = this;
        let results = tokenTargetData.getModifyResults(attrName);
        let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());

        attributeHandler.addGetAttrCallback(function (attrHandler) {
            results.current = parseInt(tokenNoteReference[attrName].current);
            results.max = parseInt(tokenNoteReference[attrName].max);
            modCallback(results, value, attrHandler, tokenTargetData);
            finishCallback(results, attrHandler, "", tokenTargetData);
        });
    }

    modifyResourceAttribute(attributeHandler, attributeName, value, modCallback, finishCallback) {
        let tokenTargetData = this;
        let results = tokenTargetData.getModifyResults(attributeName);

        let attributeVar = WuxDef.GetVariable(attributeName);
        attributeHandler.addAttribute(attributeVar);
        attributeHandler.addGetAttrCallback(function (attrHandler) {
            results.current = attrHandler.parseInt(attributeVar, 0, false);
            results.max = attrHandler.parseInt(attributeVar, 0, true);
            modCallback(results, value, attrHandler, tokenTargetData);
            finishCallback(results, attrHandler, attributeVar, tokenTargetData);
        });
    }

    addModifierToAttribute(results, value, attrHandler, tokenTargetData) {
        tokenTargetData.addModifierToAttributeNoCap(results, value, attrHandler, tokenTargetData);
        if (results.newValue > results.max) {
            results.remainder = results.newValue - results.max;
            results.newValue = results.max;
        }
        return results;
    }

    addModifierToAttributeNoCap(results, value, attrHandler) {
        if (value == "max") {
            results.newValue = results.max;
            return;
        }
        
        if (isNaN(value)) {
            // likely a variable. Look it up
            value = attrHandler.parseInt(value, 0, false);
        }
        
        if (isNaN(value)) {
            Debug.LogError(`[AddMod] Value for ${results.name} is returning as NaN. Aborting.`);
            return;
        }

        let newValue = parseInt(value);
        if (isNaN(newValue)) {
            // likely a variable. Look it up
            
            newValue = attrHandler.parseInt(value, 0, false);
        }

        results.newValue = results.current + newValue;
        if (results.newValue < 0) {
            results.remainder = results.newValue;
            results.newValue = 0;
        }
    }

    setModifierToAttribute(results, value, attrHandler) {
        if (value == "max") {
            results.newValue = results.max;
            return;
        }
        results.newValue = parseInt(value);
        if (isNaN(results.newValue)) {
            // likely a variable. Look it up
            results.newValue = attrHandler.parseInt(value, 0, false);
        }

        if (results.newValue < 0) {
            results.remainder = results.newValue;
            results.newValue = 0;
        } else if (results.newValue > results.max) {
            results.remainder = results.newValue - results.max;
            results.newValue = results.max;
        }
    }
}

class TokenTargetEffectsData {
    constructor(tokenTargetData) {
        this.tokenTargetData = tokenTargetData;
        this.effectMessages = [];
        this.damageRolls = [];
        this.halveAllDamage = false;
        this.statusEffects = {};
        this.spentSurge = false;
        this.removeStatusMessage = "";
        this.willBreakButtonAdded = false;
    }

    addMessage(message) {
        if (message != undefined && message != "") {
            this.effectMessages.push(message);
        }
    }

    addDamageRoll(damageRoll) {
        for (let i = 0; i < this.damageRolls.length; i++) {
            if (this.damageRolls[i].isSame(damageRoll)) {
                this.damageRolls[i].addDieRoll(damageRoll);
                return;
            }
        }

        this.damageRolls.push(damageRoll);
    }

    performDamageRolls(attrGetter, attrSetter, willBreakEffect) {
        let tokenTargetEffect = this;
        let hasShielded = false;
        
        this.damageRolls.forEach(function (damageRoll) {
            switch (damageRoll.damageType) {
                case "HP Heal":
                    tokenTargetEffect.takeHpHealing(attrSetter, damageRoll);
                    break;
                case "Will":
                case "Psyche":
                    tokenTargetEffect.modifyDamageRollHalveDamage(damageRoll);
                    tokenTargetEffect.modifyDamageRollResistanceCheck(damageRoll);
                    tokenTargetEffect.takeWillDamage(attrSetter, damageRoll, willBreakEffect);
                    break;
                case "Will Overflow":
                    Debug.Log("Overflow action");
                    tokenTargetEffect.takeWillOverflowDamage(attrSetter, damageRoll);
                    break;
                case "Will Heal":
                    tokenTargetEffect.takeWillHealing(attrSetter, damageRoll);
                    break;
                case "Will Full Heal":
                    tokenTargetEffect.takeWillFullHealing(attrSetter);
                    break;
                default:
                    tokenTargetEffect.modifyDamageRollHalveDamage(damageRoll);
                    tokenTargetEffect.modifyDamageRollArmorAndResistanceCheck(damageRoll, attrSetter);
                    if (tokenTargetEffect.modifyDamageRollShieldedCheck(damageRoll, attrSetter, "Stat_Shielded", "Shielded")) {
                        hasShielded = true;
                    }
                    
                    tokenTargetEffect.modifyDamageRollMantleCheck(damageRoll, attrSetter);
                    if (damageRoll.total > 0) {
                        tokenTargetEffect.takeHpDamage(attrSetter, damageRoll);
                    }
            }
        });
        
        if (hasShielded) {
            tokenTargetEffect.effectMessages.push(`Removed Shielded status.`);
            tokenTargetEffect.tokenTargetData.removeStatus(attrSetter, "Stat_Shielded");
        }
    }
    modifyDamageRollHalveDamage(damageRoll) {
        if (this.halveAllDamage) {
            damageRoll.addModToRoll(-1 * Math.floor(damageRoll.total / 2), "Failed Check");
        }
    }
    modifyDamageRollArmorAndResistanceCheck(damageRoll, attrSetter) {
        let damageReductionTotal = 0;
        let damageReductionModifiers = "";
        if (!damageRoll.traits.includes("AP")) {
            damageReductionTotal = this.tokenTargetData.combatDetails.getArmor();
            let ironPlates = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Iron Plates");
            if (ironPlates > 0) {
                damageReductionTotal += ironPlates;
            }
            if (this.tokenTargetData.hasStatus(attrSetter, "Stat_Armored")) {
                damageReductionTotal += 2 * this.tokenTargetData.combatDetails.getCr();
            }

            if (damageReductionTotal > 0) {
                damageReductionModifiers += "Armor";
            }
        }
        
        let resistance = this.tokenTargetData.combatDetails.getResistance(damageRoll.damageType);
        if (resistance != 0) {
            damageReductionTotal += resistance;
            if (damageReductionModifiers != "") {
                damageReductionModifiers += "+";
            }
            if (resistance > 0) {
                damageReductionModifiers += `${damageRoll.damageType} Resist`;
            }
            else {
                damageReductionModifiers += `${damageRoll.damageType} Weakness`;
            }
        }

        switch(damageRoll.damageType) {
            case "Dmg_Force":
            case "Dmg_Piercing":
                let earthBlight = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Earthblight");
                if (earthBlight > 0) {
                    damageReductionTotal -= earthBlight * 2;
                }
                let sandAegis = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Sand Aegis");
                if (sandAegis > 0) {
                    damageReductionTotal += sandAegis * this.tokenTargetData.combatDetails.getCr();
                }
                break;
            case "Dmg_Cold":
                let chilled = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Chilled");
                if (chilled > 0) {
                    damageReductionTotal -= chilled * 2;
                }
                let coldAegis = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Cold Aegis");
                if (coldAegis > 0) {
                    damageReductionTotal += coldAegis * this.tokenTargetData.combatDetails.getCr();
                }
                break;
            case "Dmg_Burn":
                let burnAegis = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Burn Aegis");
                if (burnAegis > 0) {
                    damageReductionTotal += burnAegis * this.tokenTargetData.combatDetails.getCr();
                }
                break;
            case "Dmg_Energy":
                let staticked = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Static");
                if (staticked > 0) {
                    damageReductionTotal -= staticked * 2;
                }
                let shockAegis = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Shock Aegis");
                if (shockAegis > 0) {
                    damageReductionTotal += shockAegis * this.tokenTargetData.combatDetails.getCr();
                }
                break;
        }
        
        if (damageReductionTotal != 0) {
            if (damageReductionTotal > damageRoll.total / 2) {
                damageReductionTotal = Math.floor(damageRoll.total / 2);
            }
            damageRoll.addModToRoll(-1 * damageReductionTotal, damageReductionModifiers);
        }
    }
    modifyDamageRollResistanceCheck(damageRoll) {
        let resistance = this.tokenTargetData.combatDetails.getResistance(damageRoll.damageType);
        if (resistance != 0) {
            let damageReductionModifiers = "";
            if (resistance > 0) {
                damageReductionModifiers = `${damageRoll.damageType} Resist`;
            }
            else {
                damageReductionModifiers = `${damageRoll.damageType} Weakness`;
            }
            if (resistance > damageRoll.total / 2) {
                resistance = Math.floor(damageRoll.total / 2);
            }
            damageRoll.addModToRoll(-1 * resistance, damageReductionModifiers);
        }
    }
    getDamageRollResistanceModifiers(damageRoll, attrSetter) {
        
    }
    modifyDamageRollShieldedCheck(damageRoll, attrSetter, statusName, modName) {
        if (this.tokenTargetData.hasStatus(attrSetter, statusName)) {
            damageRoll.addModToRoll(-1 * Math.floor(damageRoll.total / 2), modName);
            return true;
        }
    }
    modifyDamageRollMantleCheck(damageRoll, attrSetter) {
        let mantle = this.tokenTargetData.getStatusRank(attrSetter, "Stat_Mantle");
        if (mantle > 0) {
            let mantleShielding = Math.ceil(damageRoll.total / 2);
            let mantleNewValue = mantle - mantleShielding;
            this.effectMessages.push(`${this.tokenTargetData.displayName}'s mantle takes ` +
                `${Format.ShowTooltip(damageRoll.total, damageRoll.message)} ${damageRoll.damageType} damage.`);
            if (mantleNewValue <= 0) {
                this.effectMessages.push(`${this.tokenTargetData.displayName}'s mantle is broken!`);
                this.tokenTargetData.removeStatus(attrSetter, "Stat_Mantle");
                damageRoll.addModToRoll(-1 * mantle, "Mantle");
            } else {
                this.tokenTargetData.setStatus(attrSetter, "Stat_Mantle", mantleNewValue);
                damageRoll.addModToRoll(-1 * mantleShielding, "Mantle");
            }
        }
    }

    tryAddStatusResult(statusDefinitionName, type, rank, attrHandler) {
        if (type == "add" || type == "set") {
            let aflame;
            let vined;
            switch (statusDefinitionName) {
                case "Stat_Aflame":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Chilled")) {
                        this.effectMessages.push("Aflame removes Chilled from target");
                        rank *= 2;
                    }
                    vined = this.tokenTargetData.getStatusRank(attrHandler, "Stat_Vined");
                    if (vined > 0) {
                        this.effectMessages.push("Target is Vined. Adding Vine ranks to Aflame and taking damage.");
                        rank += vined;
                        this.addStatusResult("Stat_Vined", "remove", vined);
                        this.takeAflameEffect(attrHandler, vined);
                    }
                    break;
                case "Stat_Vined":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Soaked")) {
                        this.effectMessages.push("Target is Soaked. Doubling Vined ranks.");
                        this.addStatusResult("Stat_Soaked", "remove", 1);
                        rank *= 2;
                    }
                    aflame = this.tokenTargetData.getStatusRank(attrHandler, "Stat_Soaked");
                    if (aflame > 0) {
                        this.effectMessages.push("Target is Aflame. Adding Vine ranks to Aflame and taking damage.");
                        this.addStatusResult("Aflame", "add", rank);
                        this.takeAflameEffect(attrHandler, rank);
                        return;
                    }
                    break;
                case "Stat_Chilled":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Aflame")) {
                        this.effectMessages.push("Aflame removes Chilled from target");
                        return;
                    }
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Soaked")) {
                        this.effectMessages.push("Target is Soaked. Doubling Chilled ranks.");
                        this.addStatusResult("Stat_Soaked", "remove", 1);
                        rank *= 2;
                    }
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Magnetized")) {
                        this.effectMessages.push("Target is Magnetized. Doubling Chilled ranks.");
                        this.addStatusResult("Stat_Magnetized", "remove", 1);
                        rank *= 2;
                    }
                    break;
                case "Stat_Cold Aegis":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Iron Plates")) {
                        this.effectMessages.push("Target has Iron Plates. Doubling Cold Aegis ranks.");
                        rank *= 2;
                    }
                    break;
                case "Stat_Static":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Magnetized")) {
                        this.effectMessages.push("Target is Magnetized. Doubling Static ranks.");
                        this.addStatusResult("Stat_Magnetized", "remove", 1);
                        rank *= 2;
                    }
                    break;
                case "Stat_Iron Plates":
                    if (this.tokenTargetData.hasStatus(attrHandler, "Stat_Sand Aegis")) {
                        this.effectMessages.push("Target has Sand Aegis. Doubling Iron Plate ranks.");
                        rank *= 2;
                    }
                    break;
            }
        }
        
        this.addStatusResult(statusDefinitionName, type, rank);
    }
    addStatusResult(statusDefinitionName, type, rank) {
        if (this.statusEffects[statusDefinitionName] == undefined) {
            this.statusEffects[statusDefinitionName] = {
                type: type,
                rank: parseInt(rank)
            };
            return;
        }

        switch (type) {
            case "add":
                let existingType = this.statusEffects[statusDefinitionName].type;
                let existingRank = this.statusEffects[statusDefinitionName].rank;
                if (existingType == "set") {
                    this.statusEffects[statusDefinitionName].rank = existingRank + parseInt(rank);
                } else if (existingType == "add") {
                    this.statusEffects[statusDefinitionName].rank = existingRank + parseInt(rank);
                } else if (existingType == "remove") {
                    this.statusEffects[statusDefinitionName].type = "set";
                    this.statusEffects[statusDefinitionName].rank = parseInt(rank);
                }
                break;
            default:
                this.statusEffects[statusDefinitionName].type = type;
                this.statusEffects[statusDefinitionName].rank = parseInt(rank);
                break;
        }
    }
    performStatusResults(attrSetter) {
        let tokenTargetEffect = this;
        tokenTargetEffect.tokenTargetData.refreshCombatDetails(attrSetter);

        attrSetter.addGetAttrCallback(function (attrHandler) {
            let tokenNoteReference = new TokenNoteReference(tokenTargetEffect.tokenTargetData.getTokenNote());
            for(let statusName in tokenTargetEffect.statusEffects) {
                let statusInfo = tokenTargetEffect.statusEffects[statusName];
                let statusDefinitionName = statusName;
                let task = statusInfo.type;
                let rank = statusInfo.rank;
                switch (task) {
                    case "set":
                        tokenNoteReference.statusHandler.setStatus(statusDefinitionName, rank);
                        break;
                    case "add":
                        tokenNoteReference.statusHandler.addStatus(statusDefinitionName, rank);
                        break;
                    case "remove":
                        tokenNoteReference.statusHandler.removeStatus(statusDefinitionName);
                        break;
                }
            }
            tokenTargetEffect.tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
            tokenTargetEffect.tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
        });
    }


    hasSurged() {
        return this.spentSurge;
    }
    setSpendSurge() {
        this.spentSurge = true;
    }
    spendSurge(attributeHandler) {
        this.spentSurge = true;

        let targetEffect = this;
        this.tokenTargetData.addSurge(attributeHandler, -1,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} spends a Surge.`);
                tokenTargetData.applyResultsSurge(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    setRemoveStatusType(attributeHandler, statusType) {
        let targetEffect = this;
        targetEffect.removeStatusMessage = "";

        attributeHandler.addGetAttrCallback(function () {
            let tokenNoteReference = new TokenNoteReference(targetEffect.tokenTargetData.getTokenNote());
            targetEffect.removeStatusMessage = tokenNoteReference.statusHandler.getStatusDetailsMessage(targetEffect.tokenTargetData, statusType);
        });
    }

    takeHpDamage(attributeHandler, damageRoll) {
        let targetEffect = this;

        this.tokenTargetData.addHp(attributeHandler, -1 * damageRoll.total,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} takes ${Format.ShowTooltip(damageRoll.total, damageRoll.message)} ${damageRoll.damageType} damage.`);
                if (results.newValue == 0) {
                    results.remainder += results.max;
                    if (results.remainder < 1) {
                        results.remainder = 1;
                    }
                    let newAttributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                    targetEffect.takeVitalityDamage(targetEffect, newAttributeHandler, 1);
                    newAttributeHandler.run();
                    results.newValue = results.remainder;
                }
                tokenTargetData.applyResultsToHp(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeHpHealing(attributeHandler, healRoll) {
        let targetEffect = this;

        this.tokenTargetData.addHp(attributeHandler, healRoll.total,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} heals ${Format.ShowTooltip(healRoll.total, healRoll.message)} HP.`);
                tokenTargetData.applyResultsToHp(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeVitalityDamage(targetEffect, attributeHandler, damage) {
        targetEffect.effectMessages.push(`${targetEffect.tokenTargetData.displayName} loses ${damage} Vitality.`);
        this.tokenTargetData.addVitality(attributeHandler, -1 * damage,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                if (results.newValue <= 0) {
                    tokenTargetData.setDowned(true, attrHandler);
                }
                tokenTargetData.applyResultsVitality(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeWillDamage(attributeHandler, damageRoll, willBreakEffect) {
        let targetEffect = this;

        this.tokenTargetData.addWill(attributeHandler, -1 * damageRoll.total,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} takes ${Format.ShowTooltip(damageRoll.total, damageRoll.message)} will damage.`);
                if (results.remainder < 0) {
                    if (willBreakEffect != undefined && !targetEffect.willBreakButtonAdded) {
                        targetEffect.willBreakButtonAdded = true;
                        targetEffect.effectMessages.push(`<span class="sheet-wuxInlineRow">[Use Will Break Effect](${willBreakEffect.printWillBreakString()})</span> `);
                    }
                }
                tokenTargetData.applyResultsToWill(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeWillOverflowDamage(attributeHandler, damageRoll) {
        let targetEffect = this;

        let surgeVar = WuxDef.GetVariable("Surge");
        let surgeResults = this.tokenTargetData.getModifyResults(surgeVar);
        this.tokenTargetData.refreshCombatDetails(attributeHandler);
        let tokenNoteReference = {};
        if (targetEffect.tokenTargetData.isCharacter()) {
            attributeHandler.addAttribute(surgeVar);
        } else {
            tokenNoteReference = new TokenNoteReference(this.tokenTargetData.getTokenNote());
        }

        this.tokenTargetData.addWill(attributeHandler, -1 * damageRoll.total,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                tokenTargetData.applyResultsToWill(results, attrHandler, attributeVar, tokenTargetData);
                tokenTargetData.applyResultsSurge(surgeResults, attrHandler, surgeVar, tokenTargetData);
            },
            function (results, value, attrHandler) {
                if (targetEffect.tokenTargetData.isCharacter()) {
                    surgeResults.current = attrHandler.parseInt(surgeVar, 0, false);
                    surgeResults.max = attrHandler.parseInt(surgeVar, 0, true);
                } else {
                    surgeResults.current = parseInt(tokenNoteReference["surges"].current);
                    surgeResults.max = parseInt(tokenNoteReference["surges"].max);
                    Debug.Log(`Current surges for ${targetEffect.tokenTargetData.displayName} is ${surgeResults.current}/${surgeResults.max}`);
                }

                if (surgeResults.current > 0 && !isNaN(results.max)) {
                    surgeResults.newValue = surgeResults.current - 1;
                    results.newValue = results.max;
                    Debug.Log("Setting will results to " + results.newValue);
                    // if (results.newValue <= 0) {
                    //     results.newValue = 1; // we do not allow multiple willbreaks to occur. Willpower always restores to at least 1
                    // }
                    targetEffect.effectMessages.push(`${targetEffect.tokenTargetData.displayName} consumes a Surge. ` +
                        `${targetEffect.tokenTargetData.displayName} fully heals Will ` +
                        (damageRoll.total > 0 ? `then takes ${Format.ShowTooltip(damageRoll.total, damageRoll.message)} damage.` : ""));
                } else {
                    surgeResults.newValue = 0;
                    results.newValue = 0;
                    targetEffect.effectMessages.push(`${targetEffect.tokenTargetData.displayName} has no Surges remaining. Will remains at zero.`);
                }

                // set the will to max first
                return results;
            });

    }

    takeWillHealing(attributeHandler, healRoll) {
        let targetEffect = this;

        this.tokenTargetData.addWill(attributeHandler, healRoll.total,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} heals ${Format.ShowTooltip(healRoll.total, healRoll.message)} Will.`);
                tokenTargetData.applyResultsToWill(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeWillFullHealing(attributeHandler) {
        let targetEffect = this;

        this.tokenTargetData.setWillToFull(attributeHandler,
            function (results, attrHandler, attributeVar, tokenTargetData) {
                targetEffect.effectMessages.push(`${tokenTargetData.displayName} has their Will fully healed.`);
                tokenTargetData.applyResultsToWill(results, attrHandler, attributeVar, tokenTargetData);
            });
    }

    takeAflameEffect(attributeHandler, extraValue) {
        let aflame = this.tokenTargetData.getStatusRank(attributeHandler, "Stat_Aflame");
        if (extraValue != undefined && isNaN(parseInt(extraValue))) {
            aflame += parseInt(extraValue);
        }
        if (aflame > 0) {
            let roll = new DamageRoll();
            roll.rollDice(aflame, 6);
            roll.setDamageType(WuxDef.GetTitle("Dmg_Burn"));
            this.addDamageRoll(roll);
        }
    }
    takeAngeredEffect(attributeHandler) {
        if (this.tokenTargetData.hasStatus(attributeHandler, "Stat_Angered")) {
            this.takeCastWillbreakEffect(attributeHandler);
            let roll = new DamageRoll();
            roll.addModToRoll(5 + (5 * this.tokenTargetData.combatDetails.getCr()));
            roll.setDamageType("Psyche");
            this.addDamageRoll(roll);
        }
    }
    takeBleedingEffect(attributeHandler) {
        let bleeding = this.tokenTargetData.getStatusRank(attributeHandler, "Stat_Bleeding");
        if (bleeding > 0) {
            let roll = new DamageRoll();
            roll.rollDice(bleeding, 6);
            roll.setDamageType(WuxDef.GetTitle("Dmg_Tension"));
            roll.setTraits("AP");
            this.addDamageRoll(roll);
        }
    }
    takeDoubtEffect(attributeHandler) {
        if (this.tokenTargetData.hasStatus(attributeHandler, "Stat_Doubt")) {
            let roll = new DamageRoll();
            roll.addModToRoll(5 + (5 * this.tokenTargetData.combatDetails.getCr()));
            roll.setDamageType("Psyche");
            this.addDamageRoll(roll);
        }
    }
    takeFrightenedEffect(attributeHandler) {
        if (this.tokenTargetData.hasStatus(attributeHandler, "Stat_Frightened")) {
            this.takeCastWillbreakEffect(attributeHandler);
            let roll = new DamageRoll();
            roll.addModToRoll(10 + (5 * this.tokenTargetData.combatDetails.getCr()));
            roll.setDamageType("Psyche");
            this.addDamageRoll(roll);
        }
    }
    takeCastWillbreakEffect(attributeHandler) {
        let roll = new DamageRoll();
        roll.addModToRoll(5 + (5 * attributeHandler.parseInt(WuxDef.GetVariable("CR"))));
        roll.setDamageType(WuxDef.GetTitle("Dmg_Tension"));
        roll.setTraits("AP");
        this.addDamageRoll(roll);
    }
}

class TokenNoteReference {
    constructor(data) {
        this.createEmpty();
        if (data != undefined) {
            if (typeof data == "string") {
                this.importStringifiedJson(data);
            } else {
                this.importJson(data);
            }
        }
    }

    importStringifiedJson(stringifiedJSON) {
        if (stringifiedJSON == undefined || stringifiedJSON == "") {
            return;
        }
        try {
            let json = JSON.parse(stringifiedJSON);
            this.importJson(json);
        } catch {
            Debug.LogError("[TokenNoteReference] Unable to parse token note JSON");
        }
    }

    createEmpty() {
        this.statusHandler = new StatusHandler();
        this.surges = {current: 0, max: 0};
        this.vitality = {current: 0, max: 0};
        this.teamIndex = 0;
        
    }

    importJson(json) {
        if (json.statusHandler == undefined) {
            this.statusHandler = new StatusHandler();
        } else {
            this.statusHandler = new StatusHandler(json.statusHandler);
        }
        this.surges = json.surges == undefined ? {current: 0, max: 0} : json.surges;
        this.vitality = json.vitality == undefined ? {current: 0, max: 0} : json.vitality;
        this.teamIndex = json.teamIndex ?? 0;
    }
}

var TargetReference = TargetReference || (function () {
    'use strict';

    var schemaVersion = "0.1.4",

        checkInstall = function () {
            if (!state.hasOwnProperty('TargetReference') || state.TargetReference.version != schemaVersion) {
                log(`Setting Wuxing Target version to v${schemaVersion}`);
                state.TargetReference = {
                    version: schemaVersion,
                    activeCharacters: getDefaultActiveCharacters()
                };
            }
        },

        // Input Commands
        // ---------------------------

        handleInput = function (msg, tag, content) {
            switch (tag) {
                case "!actcheck":
                    commandCheckActiveTargets(msg);
                    break;
                case "!actadd":
                    commandAddCharacter(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!actrem":
                    commandRemoveCharacter(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!actclr":
                    commandClearActiveTargets();
                    break;
                case "!tokenoptions":
                    commandShowTokenOptions(msg);
                    break;
                case "!partyoptions":
                    commandShowPartyOptions(msg);
                    break;
                case "!mcheckstatus":
                    content = getMessageTarget(content);
                    commandCheckStatus(msg, content.targets);
                    break;
                case "!tconflictstate":
                    commandSetConflictState(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!taddtoconflict":
                    commandAddToConflict(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tss":
                    commandSetRequestCheck(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tinfluence":
                    commandSetInfluence(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tsetadv":
                    commandSetAdvantage(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tpp":
                    commandAddTrainingPoints(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!txp":
                    commandAddExperience(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!ten":
                    commandAddEnergy(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tmovereset":
                    commandResetMoveCharge(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!tmove":
                    commandAddMoveCharge(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!tdash":
                    commandAddDash(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!tfullheal":
                    commandFullHeal(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!pfullheal":
                    content = getTeamTargets(content);
                    commandFullHeal(msg, content.targets);
                    break;
                case "!thealsurge":
                    commandHealSurge(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!phealsurge":
                    content = getTeamTargets(content);
                    commandHealSurge(msg, content.targets, content.content);
                    break;
                case "!thealvit":
                    commandHealVitality(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!phealvit":
                    content = getTeamTargets(content);
                    commandHealVitality(msg, content.targets, content.content);
                    break;
                case "!tconditional":
                    commandTargetConditional(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                case "!tresetsocial":
                    commandResetSocial(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!maddstatuslist":
                    content = getMessageTarget(content);
                    commandAddStatusList(msg, content.targets, content.content);
                    break;
                case "!maddstatus":
                    content = getMessageTarget(content);
                    commandAddStatus(msg, content.targets, content.content);
                    break;
                case "!mremstatus":
                    content = getMessageTarget(content);
                    commandRemoveStatus(msg, content.targets, content.content);
                    break;
                case "!tdetails":
                    commandUpdateCombatDetails(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!tharddetails":
                    commandUpdateCombatDetailsHard(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!treset":
                    commandResetToken(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!tshowgroup":
                    commandShowGroup(msg.who, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!cshowgroup":
                    content = getCharacterSheetTarget(content);
                    commandShowGroup(msg.who, content.targets, content.content);
                    break;
                case "!tskillgroupcheck":
                    commandRollSkillGroupCheck(msg.who, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!cskillgroupcheck":
                    content = getCharacterSheetTarget(content);
                    commandRollSkillGroupCheck(msg.who, content.targets, content.content);
                    break;
                case "!intro":
                    commandIntroduce(msg, TokenReference.GetTokenTargetDataArray(msg));
                    break;
                case "!tgenname":
                    commandGenerateName(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
            }
        },

        commandCheckActiveTargets = function (msg) {
            if (state.WuxConflictManager == undefined || state.WuxConflictManager.teams == undefined) {
                let messageObject = new SystemInfoMessage("No active conflict.");
                messageObject.setSender("System");
                WuxMessage.SendToSenderAndGM(messageObject, msg);
                return;
            }

            if (state.TargetReference.activeCharacters.length == 0) {
                let messageObject = new SystemInfoMessage("No active characters.");
                messageObject.setSender("System");
                WuxMessage.SendToSenderAndGM(messageObject, msg);
                return;
            }

            let allyTeam = getActiveTargetsOnTeam(0);
            let enemyTeam = getActiveTargetsOnTeam(1);
            let outputMessage = [];
            outputMessage.push(`Ally Team: ${getTargetListNames(allyTeam, true)}`);
            outputMessage.push(`Enemy Team: ${getTargetListNames(enemyTeam, true)}`);

            let messageObject = new SystemInfoMessage(outputMessage);
            messageObject.setSender("System");
            WuxMessage.SendToSenderAndGM(messageObject, msg);
        },

        commandAddCharacter = function (msg, targets, teamIndex) {
            _.each(targets, function (tokenTargetData) {
                tokenTargetData.setTeamIndex(teamIndex);
                addToActiveCharacters(tokenTargetData);
            });

            sendTokenUpdateMessage(msg, targets, ` added as ${state.WuxConflictManager.teams[teamIndex].name} unit(s)`);
        },

        commandRemoveCharacter = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                removeActiveTargetData(tokenTargetData.tokenId);
            });
            sendTokenUpdateMessage(msg, targets, " removed from active characters");
        },

        commandClearActiveTargets = function () {
            clearActiveTargetData();
        },

        getCharacterSheetTarget = function (content) {
            let output = {
                content: "",
                targets: []
            }
            let contentSplit = content.split("@@@");
            output.content = contentSplit[1];

            let target = getTargetDataByName(contentSplit[0]);
            if (target != undefined) {
                output.targets.push(target);
            }

            return output;
        },

        getMessageTarget = function (content) {
            let output = {
                content: "",
                targets: []
            }
            let contentSplit = content.split("@@@");
            output.content = contentSplit[1];

            let target = getTokenTargetData(contentSplit[0]);
            if (target != undefined) {
                output.targets.push(target);
            }

            return output;
        },

        getTeamTargets = function (content) {
            let output = {
                content: "",
                targets: []
            }
            let contentSplit = content.split("@@@");
            output.content = contentSplit[1];

            let target = getActiveTargetsOnTeam(contentSplit[0]);
            if (target != undefined) {
                output.targets.push(target);
            }

            return output;
        },

        commandShowTokenOptions = function (msg) {
            let sender = msg.who;

            let output = "";
            output += tokenOptionTitle("Token State");
            output += tokenOptionButton("Update Tooltip", "tdetails");
            if (playerIsGM(msg.playerid)) {
                output += tokenOptionButton("Hard Update", "tharddetails");
                output += tokenOptionButton("Gen Name", "tgenname");
                output += tokenOptionButton("Reset Token", "treset");
                output += tokenOptionButton("Remove From Conflict", "actrem");
            }
            if (!playerIsGM(msg.playerid)) {
                output += tokenOptionButton("Prep4 Battle", `tconflictstate Battle@0`);
                output += tokenOptionButton("Prep4 Social", `tconflictstate Social@0`);
                output += tokenOptionButton("Add to Conflict", `taddtoconflict 0`);
            } else {
                output += tokenOptionButton("Prep4 Battle", `tconflictstate Battle@?{Set team index|0}`);
                output += tokenOptionButton("Prep4 Social", `tconflictstate Social@?{Set team index|0}`);
                output += tokenOptionButton("Add to Conflict", `taddtoconflict ?{Set team index|0}`);
            }

            output += tokenOptionSpacer();
            output += tokenOptionTitle("General Options");
            output += tokenOptionButton("Set Advantage", `tsetadv ?{Set Advantage value. Negative values become disadvantage|1}`);
            if (playerIsGM(msg.playerid)) {
                output += tokenOptionButton("Give TP", `tpp ?{Amount of TP|0}`);
                output += tokenOptionButton("Give XP", `txp ?{Amount of XP|0}`);
            }

            let conditionals = `Aflame|Angered|Bleeding|Frightened|Willbreak Cast`;
            switch (state.WuxConflictManager.conflictType) {
                case "Battle":
                    output += tokenOptionSpacer();
                    output += tokenOptionTitle("Combat Stat Options");
                    if (playerIsGM(msg.playerid)) {
                        output += tokenOptionButton("Full Heal", "tfullheal");
                    }
                    output += tokenOptionButton("Add Energy", "ten ?{How much energy to add?|1}");
                    output += tokenOptionButton("Add Surge", "thealsurge ?{How much surge to add?|1}");
                    output += tokenOptionButton("Add Vitality", "thealvit ?{How much vitality to add?|1}");
                    output += tokenOptionButton("Take Condition Effect", `tconditional ?{Choose your conditional|${conditionals}`);

                    output += tokenOptionSpacer();
                    output += tokenOptionTitle("Combat Move Options");
                    output += tokenOptionButton("Reset Move", "tmovereset");
                    output += tokenOptionButton("Add Move Charge", "tmove ?{How much move charge to add?|1}");
                    output += tokenOptionButton("Add Dash", "tdash");
                    break;
                case "Social":
                    output += tokenOptionSpacer();
                    output += tokenOptionTitle("Social Stat Options");
                    if (playerIsGM(msg.playerid)) {
                        output += tokenOptionButton("Reset Social", "tresetSocial");
                    }
                    let requestTypes = WuxDef.Filter([new DatabaseFilterData("group", "RequestType")]);
                    let requestList = "";
                    for (let i = 0; i < requestTypes.length; i++) {
                        if (requestList != "") {
                            requestList += "|";
                        }
                        requestList += requestTypes[i].getTitle();
                    }
                    output += tokenOptionButton("Add Energy", "ten ?{How much energy to add?|1}");
                    output += tokenOptionButton("Take Condition Effect", `tconditional ?{Choose your conditional|${conditionals}`);
                    output += tokenOptionButton("Request Threshold", `tss ?{Set the difficulty of the request|${requestList}}`);
                    output += tokenOptionButton("Set Influence", "tinfluence ?{Set the influence level of the character|0}");
            }

            let senderMessage = new SystemInfoMessage(output);
            senderMessage.setSender(sender);
            WuxMessage.Send(senderMessage, sender);
        },

        commandShowPartyOptions = function (msg) {
            let sender = msg.who;

            let output = "";
            output += tokenOptionTitle("Party State");
            output += tokenOptionButton("Check", "actcheck");
            output += tokenOptionButton("Clear All", "actclr");

            output += tokenOptionSpacer();
            output += tokenOptionTitle("Conflict Options");
            output += tokenOptionButton("Start Battle", "cmbstartbattle");
            output += tokenOptionButton("Start Social", "cmbstartsocial");
            output += tokenOptionButton("Roll Init", "rollinit");
            output += tokenOptionButton("Round", "startround");
            output += tokenOptionSpacer();
            output += tokenOptionButton("Conflict XP", "conflictxp");
            output += tokenOptionButton("End", "endcombat");

            output += tokenOptionSpacer();
            // output += tokenOptionTitle("Combat Stat Options");
            // output += tokenOptionButton("Full Heal", "pfullheal ?{Team index|0}@@@");
            // output += tokenOptionButton("Add Surge", "phealsurge ?{Team index|0}@@@?{How much surge to add?|1}");
            // output += tokenOptionButton("Add Vitality", "phealvit ?{Team index|0}@@@?{How much vitality to add?|1}");

            if (playerIsGM(msg.playerid)) {
                const locationTypes = WuxDef.Filter(new DatabaseFilterData("group", "LocationType"));
                const locationOptions = locationTypes.map(function (lt) { return lt.title; }).join("|");
                output += tokenOptionSpacer();
                output += tokenOptionTitle("Adventure Options");
                output += tokenOptionButton("Adventure Options", `adventureoptions ?{Choose Location|${locationOptions}}|||?{Water Source|No Water|Freshwater|Saltwater}`);
                output += tokenOptionButton("Rest", "rest");
                output += tokenOptionButton("Start Cooking", "startcooking");
                output += tokenOptionButton("Cook", "cook");
                output += tokenOptionButton("End Cooking", "endcooking");
                const meals = WuxItems.Filter([new DatabaseFilterData("group", "Meal")]);
                if (meals.length > 0) {
                    const mealOptions = meals.map(function (m) { return m.name; }).join("|");
                    output += tokenOptionButton("Give a Meal", `givemeal ?{Choose Meal|${mealOptions}}|||?{Savoury?|No|Yes,savoury}`);
                }
            }

            let senderMessage = new SystemInfoMessage(output);
            senderMessage.setSender(sender);
            WuxMessage.Send(senderMessage, sender);
        },

        commandCheckStatus = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let outputMessage;
                let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
                outputMessage = tokenNoteReference.statusHandler.getStatusDetailsMessage(tokenTargetData, "All", true);
                
                let messageObject = new SystemInfoMessage(outputMessage);
                messageObject.setSender("System");
                WuxMessage.SendToSender(messageObject, msg);
            });
        },

        tokenOptionTitle = function (title) {
            return `<div style='font-weight: bold'>${title}</div>`;
        },

        tokenOptionSpacer = function () {
            return `<div>&nbsp</div>`;
        },

        tokenOptionButton = function (name, message) {
            return `<span class="sheet-wuxInlineRow">[${name}](!${message})</span> `;
        },

        commandSetConflictState = function (msg, targets, content) {
            let contentSplit = content.split("@");
            let conflictState = contentSplit[0];
            let teamIndex = contentSplit.length > 1 && !isNaN(parseInt(contentSplit[1])) ? parseInt(contentSplit[1]) : 0;

            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.setTeamIndex(teamIndex);
                addToActiveCharacters(tokenTargetData);
                TokenReference.SetTokenForConflict(conflictState, tokenTargetData, attributeHandler);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, ` set to ${conflictState} state as ${state.WuxConflictManager.teams[teamIndex].name} unit(s)`);
        },

        // Adds a token to a team and to the active conflict without running battle/social
        // setup — for tokens that are already prepped and shouldn't have their bars/statuses reset.
        commandAddToConflict = function (msg, targets, content) {
            let teamIndex = !isNaN(parseInt(content)) ? parseInt(content) : 0;

            _.each(targets, function (tokenTargetData) {
                tokenTargetData.setTeamIndex(teamIndex);
                addToActiveCharacters(tokenTargetData);
            });

            sendTokenUpdateMessage(msg, targets, ` added to conflict as ${state.WuxConflictManager.teams[teamIndex].name} unit(s) without resetting their token`);
        },

        commandSetRequestCheck = function (msg, targets, content) {
            let requestTypes = WuxDef.Filter([new DatabaseFilterData("group", "RequestType")]);
            let favorValue = 0;
            for (let i = 0; i < requestTypes.length; i++) {
                if (content == requestTypes[i].getTitle()) {
                    favorValue = requestTypes[i].formula.getValue();
                    break;
                }
            }
            
            if (favorValue == 0) {
                Debug.LogError(`Could not find request type ${content}`);
                return;
            }
            
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.setMaxFavor(attributeHandler, favorValue);
                attributeHandler.run();
            });
            sendTokenUpdateMessage(msg, targets, ` Request set to ${content}. Max Favor set to ${favorValue}.`);
        },
        
        commandSetInfluence = function (msg, targets, content) {
            let rank = parseInt(content);
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                if (rank > 0) {
                    tokenTargetData.removeStatus(attributeHandler, "Stat_Oppositional");
                    tokenTargetData.addStatus(attributeHandler, "Stat_Agreeable", rank);
                }
                else if (rank < 0) {
                    tokenTargetData.removeStatus(attributeHandler, "Stat_Agreeable");
                    tokenTargetData.addStatus(attributeHandler, "Stat_Oppositional", rank);
                }
                else {
                    tokenTargetData.removeStatus(attributeHandler, "Stat_Agreeable");
                    tokenTargetData.removeStatus(attributeHandler, "Stat_Oppositional");
                }
                attributeHandler.run();
            });
            
            if (rank > 0) {
                sendTokenUpdateMessage(msg, targets, `: Added ${WuxDef.GetTitle("Stat_Agreeable")} Rank ${rank}`);
            }
            else if (rank < 0) {
                sendTokenUpdateMessage(msg, targets, `: Added ${WuxDef.GetTitle("Stat_Oppositional")} Rank ${rank}`);
            }
            else {
                sendTokenUpdateMessage(msg, targets, `: Removed all Influence modifiers`);
            }
        },

        commandSetAdvantage = function (msg, targets, content) {
            let value = parseInt(content);
            if (!isNaN(value) || value == 0) {
                value = false;
            }
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.setAdvantageIcon(content);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${content} EN`);
        },

        commandAddTrainingPoints = function (msg, targets, content) {
            let value = parseInt(content);
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addModNoCap("PP", attributeHandler, value,
                    function (results, attrHandler, attributeVar) {
                        attrHandler.addUpdate(attributeVar, results.newValue, false);
                    });
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${value >= 0 ? "+" : "-"}${value} PP`);
        },

        commandAddExperience = function (msg, targets, content) {
            let value = parseInt(content);
            let xpDefinition = WuxDef.Get("XP");
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addModNoCap("XP", attributeHandler, value,
                    function (results, attrHandler, attributeVar) {
                        attrHandler.addUpdate(attributeVar, results.newValue, false);
                    });
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${value >= 0 ? "+" : "-"}${value} ${xpDefinition.getTitle()}`);
        },

        commandAddEnergy = function (msg, targets, content) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addEnergy(attributeHandler, content);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${content} EN`);
        },

        commandResetMoveCharge = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.setMoveCharge(attributeHandler, 0);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: Move Charge reset`);
        },

        commandAddMoveCharge = function (msg, targets, content) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addMoveCharge(attributeHandler, content);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${content} Move Charge`);
        },

        commandAddDash = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addDash(attributeHandler, function (results, attrHandler, attributeVar) {
                    attrHandler.addUpdate(attributeVar, results.newValue, false);
                    tokenTargetData.setTurnIcon(results.newValue);
                    sendTokenUpdateMessage(msg, [tokenTargetData], ` dashes for ${results.newValue}`);
                });
                attributeHandler.run();
            });
        },

        commandFullHeal = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.setHpToFull(attributeHandler);
                tokenTargetData.setWillToFull(attributeHandler);
                tokenTargetData.removeAllStatus(attributeHandler);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: fully healed`);
        },

        commandHealSurge = function (msg, targets, content) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addSurge(attributeHandler, content);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${content} Surge`);
        },

        commandHealVitality = function (msg, targets, content) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addVitality(attributeHandler, content);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: ${content} Vitality`);
        },

        commandTargetConditional = function (msg, targets, content) {
            let messages = [];
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                let tokenEffect = new TokenTargetEffectsData(tokenTargetData);
                
                switch (content) {
                    case "Aflame":
                        tokenEffect.takeAflameEffect(attributeHandler);
                        break;
                    case "Angered":
                        tokenEffect.takeAngeredEffect(attributeHandler);
                        break;
                    case "Bleeding":
                        tokenEffect.takeBleedingEffect(attributeHandler);
                        break;
                    case "Frightened":
                        tokenEffect.takeFrightenedEffect(attributeHandler);
                        break;
                    case "Willbreak Cast":
                        tokenEffect.takeCastWillbreakEffect(attributeHandler);
                        break;
                }
                
                attributeHandler.addFinishCallback(function (attrGetter) {
                    let newAttributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);

                    tokenTargetData.performDamageRolls(attrGetter, newAttributeHandler);
                    newAttributeHandler.addFinishCallback(function () {
                        messages = messages.concat(tokenTargetData.effectMessages);
                    })
                    newAttributeHandler.run();
                });
                attributeHandler.run();
            });

            let systemMessage = new SystemInfoMessage(messages);
            systemMessage.setSender("System");
            WuxMessage.Send(systemMessage);
        },

        commandResetSocial = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.emptyFavor(attributeHandler);
                tokenTargetData.setWillToFull(attributeHandler);
                tokenTargetData.emptyImpatience(attributeHandler);
                tokenTargetData.removeAllStatus(attributeHandler);
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: social data reset`);
        },

        commandAddStatusList = function (msg, targets, content) {
            _.each(targets, function (tokenTargetData) {
                let outputMessage = tokenTargetData.showAddStatusList(content);

                let messageObject = new SystemInfoMessage(outputMessage);
                messageObject.setSender("System");
                WuxMessage.SendToSender(messageObject, msg);
            });
        },

        commandAddStatus = function (msg, targets, content) {
            let statusType = content.split(";")[0];
            let statusName = WuxDef.GetTitle(statusType);
            let statusValue = 0;
            if (content.split(";").length > 1) {
                statusValue = parseInt(content.split(";")[1]);
                statusName += ` [${statusValue}]`;
            }
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.addStatus(attributeHandler, statusType, statusValue);
                attributeHandler.run();
            });
            sendTokenUpdateMessage(msg, targets, `: ${statusName} status added`);
        },
        
        commandRemoveStatus = function (msg, targets, content) {
            let statusType = content.split(";")[0];
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.removeStatus(attributeHandler, statusType);
                attributeHandler.run();
            });
            
            sendTokenUpdateMessage(msg, targets, `: ${WuxDef.GetTitle(statusType)} status removed`);
        },

        commandUpdateCombatDetails = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.refreshCombatDetails(attributeHandler);
                attributeHandler.addGetAttrCallback(function (attrHandler) {
                    tokenTargetData.setCombatDetails(attrHandler);
                });
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: tooltip updated`);
        },

        commandUpdateCombatDetailsHard = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                tokenTargetData.refreshCombatDetails(attributeHandler);

                let affinityVar = WuxDef.GetVariable("Affinity");
                let crVar = WuxDef.GetVariable("CR");
                let jobVar = WuxDef.GetVariable("Forme_JobSlot", 1);
                
                let braceVar = WuxDef.GetVariable("Def_Brace");
                let wardingVar = WuxDef.GetVariable("Def_Warding");
                let reflexVar = WuxDef.GetVariable("Def_Reflex");
                let evasionVar = WuxDef.GetVariable("Def_Evasion");
                let resolveVar = WuxDef.GetVariable("Def_Resolve");
                let insightVar = WuxDef.GetVariable("Def_Insight");
                let logicVar = WuxDef.GetVariable("Def_Logic");
                
                let surgeVar = WuxDef.GetVariable("Surge");
                let vitalityVar = WuxDef.GetVariable("Cmb_Vitality");
                let hvVar = WuxDef.GetVariable("Cmb_HV");
                let armorVar = WuxDef.GetVariable("Cmb_Armor");
                let burnResVar = WuxDef.GetVariable("Cmb_BurnResist");
                let coldResVar = WuxDef.GetVariable("Cmb_ColdResist");
                let energyResVar = WuxDef.GetVariable("Cmb_EnergyResist");
                let forceResVar = WuxDef.GetVariable("Cmb_ForceResist");
                let piercingResVar = WuxDef.GetVariable("Cmb_PiercingResist");
                let psycheResVar = WuxDef.GetVariable("Cmb_PsycheResist");
                let speedVar = WuxDef.GetVariable("Cmb_Mv");
                let dashVar = WuxDef.GetVariable("Cmb_MvDash");
                let weaponDamageVar = WuxDef.GetVariable("WeaponDamageVal");
                attributeHandler.addAttribute([affinityVar, crVar, jobVar, 
                    braceVar, wardingVar, reflexVar, evasionVar, resolveVar, insightVar, logicVar,
                    surgeVar, vitalityVar, hvVar, armorVar, speedVar, dashVar, weaponDamageVar,
                    burnResVar, coldResVar, energyResVar, forceResVar, piercingResVar, psycheResVar]);
                attributeHandler.addGetAttrCallback(function (attrHandler) {
                    tokenTargetData.combatDetails.onUpdateAffinity(attrHandler, attrHandler.parseString(affinityVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateCR(attrHandler, attrHandler.parseInt(crVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateJob(attrHandler, attrHandler.parseString(jobVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateDefenses(attrHandler, 
                        attrHandler.parseInt(braceVar, 0, false),
                        attrHandler.parseInt(wardingVar, 0, false),
                        attrHandler.parseInt(reflexVar, 0, false),
                        attrHandler.parseInt(evasionVar, 0, false),
                        attrHandler.parseInt(resolveVar, 0, false),
                        attrHandler.parseInt(logicVar, 0, false),
                        attrHandler.parseInt(insightVar, 0, false)
                        );
                    tokenTargetData.combatDetails.onUpdateSurges(attrHandler, attrHandler.parseInt(surgeVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateMaxSurges(attrHandler, attrHandler.parseInt(surgeVar, 0, true));
                    tokenTargetData.combatDetails.onUpdateVitality(attrHandler, attrHandler.parseInt(vitalityVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateMaxVitality(attrHandler, attrHandler.parseInt(vitalityVar, 0, true));
                    tokenTargetData.combatDetails.onUpdateHealValue(attrHandler, attrHandler.parseInt(hvVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateArmorValue(attrHandler, attrHandler.parseInt(armorVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateResistanceValues(attrHandler, attrHandler.parseInt(burnResVar, 0, false),
                        attrHandler.parseInt(coldResVar, 0, false), attrHandler.parseInt(energyResVar, 0, false),
                        attrHandler.parseInt(forceResVar, 0, false), attrHandler.parseInt(piercingResVar, 0, false),
                        attrHandler.parseInt(psycheResVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateMoveSpeedValue(attrHandler, attrHandler.parseInt(speedVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateDashSpeedValue(attrHandler, attrHandler.parseInt(dashVar, 0, false));
                    tokenTargetData.combatDetails.onUpdateWeaponDamageType(attrHandler, attrHandler.parseInt(weaponDamageVar, 0, false));
                    let tokenNoteReference = undefined;
                    if (tokenTargetData.isCharacter()) {
                        tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
                        tokenNoteReference.surges.current = attrHandler.parseInt(surgeVar, 0, false);
                        tokenNoteReference.surges.max = attrHandler.parseInt(surgeVar, 0, true);
                        tokenNoteReference.vitality.current = attrHandler.parseInt(vitalityVar, 0, false);
                        tokenNoteReference.vitality.max = attrHandler.parseInt(vitalityVar, 0, true);
                        tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));
                    }
                    tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
                });
                attributeHandler.run();
            });

            sendTokenUpdateMessage(msg, targets, `: tooltip updated`);
        },

        commandResetToken = function (msg, targets) {
            _.each(targets, function (tokenTargetData) {
                TokenReference.ResetTokenDisplay(tokenTargetData);
            });

            sendTokenUpdateMessage(msg, targets, `: token reset`);
        },

        commandShowGroup = function (sender, targets, content) {
            content = content.split(";");
            let group = content[0];
            let advantage = content.length > 1 ? content[1] : 0;
            let tableName = "";
            switch (group) {
                case "Defenses":
                    group = "Defense";
                    tableName = "Defenses";
                    break;
                case "Senses":
                    group = "Sense";
                    tableName = "Senses";
                    break;
                default:
                    tableName = content;
                    break;
            }

            let groupArray = WuxDef.Filter(new DatabaseFilterData("group", group));
            if (groupArray.length == 0) {
                Debug.LogError(`[commandShowGroup] The group (${group}) is empty!`);
            } else {
                _.each(targets, function (tokenTargetData) {
                    checkModifiers(sender, tableName, tokenTargetData, groupArray, false, advantage);
                });
            }
        },

        commandRollSkillGroupCheck = function (sender, targets, content) {
            content = content.split(";");
            let subGroup = content[0];
            let advantage = content.length > 1 ? content[1] : 0;
            let tableName = `${content}`;

            if (subGroup == "Lore") {
                _.each(targets, function (tokenTargetData) {
                    checkLore(sender, tokenTargetData, advantage);
                });
            } else {
                let groupArray = WuxDef.Filter(new DatabaseFilterData("subGroup", subGroup));
                _.each(targets, function (tokenTargetData) {
                    checkModifiers(sender, tableName, tokenTargetData, groupArray, true, advantage);
                });
            }
        },

        commandIntroduce = function (msg, targets) {
            let characters, charObj = {};
            let sender = msg.who;
            let introNameVar = WuxDef.GetVariable("FullName");
            let emotesVar = WuxDef.GetVariable("Chat_Emotes");
            let titleVar = WuxDef.GetVariable("Title");
            let ageVar = WuxDef.GetVariable("Age");
            let genderVar = WuxDef.GetVariable("Gender");
            let quickDescVar = WuxDef.GetVariable("QuickDescription");

            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);

                attributeHandler.addMod([introNameVar, emotesVar, titleVar, ageVar, genderVar, quickDescVar]);
                attributeHandler.addFinishCallback(function (attrHandler) {
                    let outfitEmoteSetData = new EmoteSetData(attrHandler.parseJSON(emotesVar));
                    let messageObject = new IntroEmoteMessage(sender, msg);
                    messageObject.setTitle(attrHandler.parseString(introNameVar));
                    let message = [];
                    let title = attrHandler.parseString(titleVar);
                    if (title != "" && title != "0") {
                        message.push(title);
                    }
                    let age = attrHandler.parseString(ageVar);
                    let gender = attrHandler.parseString(genderVar);
                    let secondLine = `${age == "0" ? "" : `Age ${age}`}${gender == "0" ? "" : `; ${gender}`}`;
                    if (secondLine != "") {
                        message.push(secondLine);
                    }
                    messageObject.message = message.join("\n");
                    messageObject.url = outfitEmoteSetData.defaultEmote;
                    messageObject.setSender(sender);
                    WuxMessage.Send(messageObject);

                    // set character data
                    characters = findObjs({
                        _id: tokenTargetData.charId,
                        _type: "character"
                    }, {caseInsensitive: true});

                    if (characters.length > 0) {
                        charObj = characters[0];
                        let bio = `<p><b>${attrHandler.parseString(introNameVar)}</b><br><i>${attrHandler.parseString(titleVar)}</i></p>`;
                        bio += `<p>Age ${attrHandler.parseString(ageVar)}; ${attrHandler.parseString(genderVar)}</p>`;
                        bio += `<p>${attrHandler.parseString(quickDescVar)}</p>`;
                        charObj.set("bio", bio);
                        charObj.set("inplayerjournals", "all");
                    }
                });
                attributeHandler.run();
            });

        },

        commandGenerateName = function (msg, targets) {
            let raceVar = WuxDef.GetVariable("Ethnicity");
            let genderVar = WuxDef.GetVariable("Gender");
            let homeRegionVar = WuxDef.GetVariable("HomeRegion");
            let sheetNameVar = WuxDef.GetVariable("SheetName");
            let outputMessage = [];

            _.each(targets, function (tokenTargetData) {
                let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);

                attributeHandler.addMod([raceVar, genderVar, homeRegionVar, sheetNameVar]);
                attributeHandler.addFinishCallback(function (attrHandler) {
                    let generator = new WuxingHumanCharacterGenerator();
                    generator.character.ancestry = attrHandler.parseString(raceVar);
                    generator.character.gender = attrHandler.parseString(genderVar);
                    generator.character.homeRegion = attrHandler.parseString(homeRegionVar);
                    generator.generateCharacter();
                    tokenTargetData.token.set("name", generator.character.firstName);
                    tokenTargetData.displayName = generator.character.firstName;

                    outputMessage.push(`${attrHandler.parseString(sheetNameVar)} Name: ${generator.character.fullName}. ` +
                        `\They have a ${generator.character.motivation} Motivation and a ${generator.character.personality} Personality.`);
                });
                attributeHandler.run();
            });

            let messageObject = new SystemInfoMessage(outputMessage);
            messageObject.setSender("System");
            WuxMessage.Send(messageObject, "GM");
        },

        sendTokenUpdateMessage = function (msg, targets, message) {
            let outputMessage = `${getTargetListNames(targets)} ${message}`;
            let messageObject = new SystemInfoMessage(outputMessage);
            messageObject.setSender("System");
            WuxMessage.SendToSenderAndGM(messageObject, msg);
        },
        
        getTargetListNames = function(targets, includeSheetName) {
            let targetNames = "";
            for (let i = 0; i < targets.length; i++) {
                if (targets.length > 1) {
                    if (i == targets.length - 1) {
                        targetNames += " and ";
                    } else if (targetNames != "") {
                        targetNames += ", ";
                    }
                }
                targetNames += `${targets[i].displayName}`;
                if (includeSheetName && targets[i].charName != targets[i].displayName) {
                    targetNames += `[${targets[i].charName}]`;
                }
            }
            return targetNames;
        },

        // Data Checkers

        checkLore = function (sender, tokenTargetData, advantage) {
            let tableData = new TableMessage([tokenTargetData.displayName, `Lore,${advantage}`]);
            let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);

            let recallVar = WuxDef.GetVariable("Recall");
            let loreBuildVar = WuxDef.GetVariable("Lore", WuxDef._build);
            attributeHandler.addMod([recallVar, loreBuildVar]);

            let dieRoll = new DieRoll();
            dieRoll.rollCheck(advantage);
            let recallResults = new DieRoll(dieRoll);

            attributeHandler.addFinishCallback(function (attrHandler) {
                let recallValue = attrHandler.parseString(recallVar, 0, false);
                recallResults.addModToRoll(recallValue);
                tableData.addRow(["Recall", `${Format.ShowTooltip(`${recallResults.total}`, recallResults.message)}`]);

                let lores = new WorkerBuildStats();
                lores.import(attrHandler.parseJSON(loreBuildVar));

                lores.iterate(function (buildStat) {
                    if (buildStat.value === "on") {
                        tableData.addRow([buildStat.name, `${Format.ShowTooltip(`${recallResults.total}`, recallResults.message)}`]);
                    } else if (parseInt(buildStat.value) > 0) {
                        let results = new DieRoll(dieRoll);
                        let value = parseInt(buildStat.value) + recallValue;
                        results.addModToRoll(value);
                        tableData.addRow([buildStat.name, `${Format.ShowTooltip(`${results.total}`, results.message)}`]);
                    }
                });
            });
            attributeHandler.run();

            let senderMessage = new SystemInfoMessage(`You've made a Lore check. Results were sent to GM.`);
            senderMessage.setSender(sender);
            WuxMessage.Send(senderMessage, sender.split(" ")[0]);

            let message = tableData.print();
            let systemMessage = new SystemInfoMessage(message);
            systemMessage.setSender(sender);
            WuxMessage.Send(systemMessage, "GM");
        },

        checkModifiers = function (sender, tableName, tokenTargetData, definitions, addSkillCheck, advantage) {
            let tableData = new TableMessage([tokenTargetData.displayName, tableName]);
            let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
            let dieRoll = new DieRoll();
            dieRoll.rollCheck(advantage);

            _.each(definitions, function (modDefinition) {
                let variable = modDefinition.getVariable();
                attributeHandler.addMod(variable);
                attributeHandler.addFinishCallback(function (attrHandler) {
                    let value = attrHandler.parseString(variable, 0, false);
                    if (addSkillCheck) {
                        let results = new DieRoll(dieRoll);
                        results.addModToRoll(value);
                        tableData.addRow([modDefinition.title, `${Format.ShowTooltip(`${results.total}`, results.message)}`]);
                    } else {
                        tableData.addRow([modDefinition.title, value]);
                    }
                });
            });
            attributeHandler.run();

            let message = tableData.print();
            let systemMessage = new SystemInfoMessage(message);
            systemMessage.setSender(sender);
            WuxMessage.Send(systemMessage);
        },

        // Active Characters

        getDefaultActiveCharacters = function () {
            return {
                targetData: {},
                nameDatabase: {}
            };
        },

        hasActiveTargets = function () {
            return Object.keys(state.TargetReference.activeCharacters.targetData).length > 0;
        },

        getActiveTargetsOnTeam = function (teamIndex) {
            let tokenTargetDataArray = [];
            iterateOverActiveTargetData(function (tokenTargetData) {
                if (tokenTargetData.getTeamIndex() == teamIndex) {
                    tokenTargetDataArray.push(tokenTargetData);
                }
            });
            return tokenTargetDataArray;
        },

        iterateOverActiveTargetData = function (callback) {
            for (let targetData in state.TargetReference.activeCharacters.targetData) {
                let tokenTargetData = TokenReference.GetTokenData(targetData);
                if (tokenTargetData != undefined && tokenTargetData.token != undefined) {
                    callback(tokenTargetData);
                }
            }
        },

        addToActiveCharacters = function (tokenTargetData) {
            if (tokenTargetData == undefined) {
                Debug.LogError(`[TargetReference][addToActiveCharacters] No target data exists.`);
                return;
            }
            if (state.TargetReference.activeCharacters.targetData.hasOwnProperty(tokenTargetData.tokenId)) {
                state.TargetReference.activeCharacters.targetData[tokenTargetData.tokenId] = tokenTargetData;
            } else {
                state.TargetReference.activeCharacters.targetData[tokenTargetData.tokenId] = tokenTargetData;
                state.TargetReference.activeCharacters.nameDatabase[tokenTargetData.charName] = tokenTargetData.tokenId;
            }
        },

        removeActiveTargetData = function (tokenId) {
            if (state.TargetReference.activeCharacters.targetData[tokenId] != undefined) {
                let targetData = state.TargetReference.activeCharacters.targetData[tokenId];
                delete state.TargetReference.activeCharacters.nameDatabase[targetData.charName];
                delete state.TargetReference.activeCharacters.targetData[tokenId];
            }
        },

        clearActiveTargetData = function () {
            state.TargetReference.activeCharacters = getDefaultActiveCharacters();
            let systemMessage = new SystemInfoMessage("Cleared Active Targets");
            systemMessage.setSender("System");
            WuxMessage.Send(systemMessage, "GM");
        },

        getTokenTargetData = function (tokenId) {
            if (state.TargetReference.activeCharacters.targetData[tokenId] == undefined) {
                return TokenReference.GetTokenData(tokenId);
            }
            return TokenReference.GetTokenData(state.TargetReference.activeCharacters.targetData[tokenId]);
        },

        getTokenTargetDataByName = function (characterName) {
            if (state.TargetReference.activeCharacters.nameDatabase[characterName] == undefined) {
                let tokenTargetData = new TokenTargetData();
                tokenTargetData.importCharacterByName(characterName);
                if (tokenTargetData.charId == "") {
                    Debug.LogError(`[TargetReference][getTargetDataByName] No target data exists for ${characterName}`);
                    return undefined;
                }
                tokenTargetData.importTokenDataOnPlayerPage();
                if (tokenTargetData.tokenId == "") {
                    Debug.LogError(`[TargetReference][getTargetDataByName] No token data exists for ${characterName}`);
                    return undefined;
                }
                return tokenTargetData;
            }
            return TokenReference.GetTokenData(state.TargetReference.activeCharacters.targetData[state.TargetReference.activeCharacters.nameDatabase[characterName]]);
        },

        getTargetDataByName = function (characterName) {
            if (state.TargetReference.activeCharacters.nameDatabase[characterName] == undefined) {
                let targetData = new TargetData();
                targetData.importCharacterByName(characterName);
                if (targetData.charId == "") {
                    Debug.LogError(`[TargetReference][getTargetDataByName] No target data exists for ${characterName}`);
                    return undefined;
                }
                return targetData;
            }
            return TokenReference.GetTokenData(state.TargetReference.activeCharacters.targetData[state.TargetReference.activeCharacters.nameDatabase[characterName]]);
        }
    ;
    return {
        CheckInstall: checkInstall,
        HandleInput: handleInput,
        HasActiveTargets: hasActiveTargets,
        GetActiveTargetsOnTeam: getActiveTargetsOnTeam,
        IterateOverActiveTargetData: iterateOverActiveTargetData,
        ClearActiveTargetData: clearActiveTargetData,
        GetTokenTargetData: getTokenTargetData,
        GetTokenTargetDataByName: getTokenTargetDataByName,
        GetTargetDataByName: getTargetDataByName
    };

}());

var TokenReference = TokenReference || (function () {
    'use strict';

    var schemaVersion = "0.1.1",

        checkInstall = function () {
            if (!state.hasOwnProperty('TokenReference') || state.TokenReference.version !== schemaVersion) {
                state.TokenReference = {
                    version: schemaVersion,
                    tokens: {}
                };
            }
            state.TokenReference.tokens = {};
        },

        // State Token Getters
        // ---------------------------

        getToken = function (tokenId) {
            let token = getObj('graphic', tokenId);
            if (token == undefined) {
                return undefined;
            }
            return token;
        },

        getTokenData = function (data) {
            if (data.tokenId != undefined) {
                return getTokenDataFromTargetData(data);
            } else {
                return getTokenDataFromId(data);
            }
        },

        getTokenDataFromTargetData = function (targetData) {
            if (state.TokenReference.tokens[targetData.tokenId] == undefined) {
                let token = getToken(targetData.tokenId);
                if (token == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Token for ${targetData.charName} not found`);
                    return undefined;
                }
                let tokenData = new TokenTargetData(token, targetData);
                if (tokenData == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Tokendata for ${targetData.charName} could not be created`);
                    return undefined;
                }
                tokenData.setDisplayName();
                addToken(tokenData, targetData.tokenId);
                return tokenData;
            } else {
                let tokenData = state.TokenReference.tokens[targetData.tokenId];
                if (tokenData == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Something went wrong. Tokendata for ${targetData.charName} is undefined`);
                    return undefined;
                }
                if (tokenData.token == undefined) {
                    let token = getToken(targetData.tokenId);
                    tokenData = new TokenTargetData(token, targetData);
                }
                tokenData.setDisplayName();
                return tokenData;
            }
        },

        getTokenDataFromId = function (tokenId) {
            if (state.TokenReference.tokens[tokenId] == undefined) {
                let token = getToken(tokenId);
                if (token == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Token for id ${tokenId} not found`);
                    return undefined;
                }
                let tokenData = new TokenTargetData(token);
                if (tokenData == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Tokendata for id ${tokenId} could not be created`);
                    return undefined;
                }
                tokenData.setDisplayName();
                addToken(tokenData, tokenId);
                return tokenData;
            } else {
                let tokenData = state.TokenReference.tokens[tokenId];
                if (tokenData == undefined) {
                    Debug.LogError(`[TokenReference][getToken] Something went wrong. Tokendata for ${tokenId} is undefined`);
                    return undefined;
                }
                if (tokenData.token == undefined) {
                    let token = getToken(tokenId.tokenId);
                    tokenData = new TokenTargetData(token, tokenId);
                }
                tokenData.setDisplayName();
                return tokenData;
            }

        },

        addToken = function (tokenData, tokenId) {
            state.TokenReference.tokens[tokenId] = tokenData;
        },

        // Data Helper
        // ---------------------------

        iterateOverSelectedTokens = function (msg, callback) {
            _.each(msg.selected, function (obj) {
                let tokenTargetData = getTokenData(obj._id);

                if (tokenTargetData != undefined) {
                    callback(tokenTargetData);
                }
            });
        },

        getTokenTargetDataArray = function (msg) {
            let tokenTargetDataArray = [];
            iterateOverSelectedTokens(msg, function (tokenTargetData) {
                tokenTargetDataArray.push(tokenTargetData);
            });
            return tokenTargetDataArray;
        },

        // Token States
        // ---------------------------

        setTokenForConflict = function (conflictType, tokenTargetData, attributeHandler) {
            if (tokenTargetData.initToken()) {
                tokenTargetData.showTokenName(true);
                tokenTargetData.showTooltip(true);

                switch (conflictType) {
                    case "Battle":
                        setTokenForBattle(tokenTargetData, attributeHandler);
                        break;
                    case "Social":
                        setTokenForSocialBattle(tokenTargetData, attributeHandler);
                        break;
                }
            }
        },
        setTokenForBattle = function (tokenTargetData, attributeHandler) {
            let hpVar = WuxDef.GetVariable("HP");
            let willpowerVar = WuxDef.GetVariable("WILL");
            let enVar = WuxDef.GetVariable("EN");
            let fullNameVar = WuxDef.GetVariable("FullName");
            attributeHandler.addAttribute([hpVar, willpowerVar, enVar, fullNameVar]);
            tokenTargetData.importTokenNoteReferenceData(attributeHandler);
            tokenTargetData.refreshCombatDetails(attributeHandler);

            attributeHandler.addGetAttrCallback(function (attrHandler) {
                tokenTargetData.setBar(1, attrHandler.getAttribute(hpVar), true, true);
                tokenTargetData.setBar(2, attrHandler.getAttribute(willpowerVar), true, true);

                if (attrHandler.parseString(fullNameVar) == "GenericOverride") {
                    tokenTargetData.unlinkBar(1);
                    tokenTargetData.unlinkBar(2);
                }

                tokenTargetData.setEnergyIcon(attrHandler.parseInt(enVar, 0, false));
                tokenTargetData.combatDetails.onUpdateDisplayStyle(attrHandler, "Battle");

                let tokenNoteReference = new TokenNoteReference(tokenTargetData.getTokenNote());
                let presetStatusDefs = WuxDef.Filter([new DatabaseFilterData("group", "Status")]).filter(def => def.presetStatus);
                for (let def of presetStatusDefs) {
                    if (def.hasRanks) {
                        let rank = attrHandler.parseInt(def.getVariable(), 0, false);
                        if (rank > 0) {
                            tokenNoteReference.statusHandler.setStatus(def.name, rank);
                        }
                    } else {
                        if (attrHandler.parseString(def.getVariable(), "", false) === "on") {
                            tokenNoteReference.statusHandler.setStatus(def.name, 1);
                            if (def.name !== "Stat_Exhausted") {
                                attrHandler.addUpdate(def.getVariable(), "");
                            }
                        }
                    }
                }
                tokenTargetData.setTokenNote(JSON.stringify(tokenNoteReference));

                tokenTargetData.setCombatDetails(attrHandler, tokenNoteReference);
            });
        },
        setTokenForSocialBattle = function (tokenTargetData, attributeHandler) {
            let patienceVar = WuxDef.GetVariable("Soc_Impatience");
            let willpowerVar = WuxDef.GetVariable("WILL");
            let favorVar = WuxDef.GetVariable("Soc_Favor");
            let enVar = WuxDef.GetVariable("EN");
            let fullNameVar = WuxDef.GetVariable("FullName");
            attributeHandler.addAttribute([patienceVar, willpowerVar, favorVar, enVar, fullNameVar]);
            tokenTargetData.importTokenNoteReferenceData(attributeHandler);
            tokenTargetData.refreshCombatDetails(attributeHandler);

            attributeHandler.addFinishCallback(function (attrHandler) {
                tokenTargetData.setBar(1, attrHandler.getAttribute(patienceVar), true, true);
                tokenTargetData.setBar(2, attrHandler.getAttribute(willpowerVar), true, true);
                tokenTargetData.setBar(3, attrHandler.getAttribute(favorVar), true, true);

                if (attrHandler.parseString(fullNameVar) == "GenericOverride") {
                    tokenTargetData.unlinkBar(1);
                    tokenTargetData.unlinkBar(2);
                    tokenTargetData.unlinkBar(3);
                }

                tokenTargetData.setEnergyIcon(attrHandler.parseInt(enVar, 0, false));
                tokenTargetData.combatDetails.onUpdateDisplayStyle(attrHandler, "Social");
                tokenTargetData.setCombatDetails(attrHandler);
            });
        },
        resetTokenDisplay = function (tokenTargetData) {
            tokenTargetData.setBar(1, undefined, true, true);
            tokenTargetData.setBar(2, undefined, true, true);
            tokenTargetData.setBar(3, undefined, true, true);
            tokenTargetData.showTokenName(false);
            tokenTargetData.showTooltip(false);
            tokenTargetData.setEnergyIcon(false);
            tokenTargetData.setTurnIcon(false);

            let attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
            tokenTargetData.refreshCombatDetails(attributeHandler);
            attributeHandler.addGetAttrCallback(function (attrHandler) {
                tokenTargetData.setDowned(false, attrHandler);
            });
            attributeHandler.addFinishCallback(function (attrHandler) {
                tokenTargetData.combatDetails.onUpdateDisplayStyle(attrHandler, "");
                tokenTargetData.setCombatDetails(attrHandler);
            });
            attributeHandler.run();
        }

    ;
    return {
        CheckInstall: checkInstall,
        IterateOverSelectedTokens: iterateOverSelectedTokens,
        GetTokenTargetDataArray: getTokenTargetDataArray,
        GetToken: getToken,
        GetTokenData: getTokenData,
        AddToken: addToken,
        SetTokenForConflict: setTokenForConflict,
        ResetTokenDisplay: resetTokenDisplay
    };

}());

on("ready", function () {
    'use strict';

    TargetReference.CheckInstall();
    TokenReference.CheckInstall();
    WuxAdventureManager.CheckInstall();
});


var WuxAdventureManager = WuxAdventureManager || (function () {
    'use strict';

    // ─── Loot Tables ────────────────────────────────────────────────────────────

    // Weights: rarity 1 = 8, 2 = 4, 3 = 2, 4 = 1 (each half the previous).
    // Returns { allRarities, rarity2Plus } where each is { slots: [rarity], byRarity: {...} }.
    const buildLootTables = function (items) {
        const byRarity = { 1: [], 2: [], 3: [], 4: [] };
        items.forEach(function (item) {
            const r = item.rarity;
            if (r >= 1 && r <= 4) byRarity[r].push(item);
        });

        const weights = { 1: 8, 2: 4, 3: 2, 4: 1 };

        const buildSlots = function (rarities) {
            let slots = [];
            rarities.forEach(function (r) {
                if (byRarity[r].length === 0) return;
                for (let w = 0; w < weights[r]; w++) {
                    slots.push(r);
                }
            });
            return slots;
        };

        return {
            allRarities: { slots: buildSlots([1, 2, 3, 4]), byRarity: byRarity },
            rarity2Plus: { slots: buildSlots([2, 3, 4]),    byRarity: byRarity }
        };
    };

    const pickFromTable = function (table) {
        if (table.slots.length === 0) return null;
        const rarity = table.slots[Math.floor(Math.random() * table.slots.length)];
        const group = table.byRarity[rarity];
        if (!group || group.length === 0) return null;
        return group[Math.floor(Math.random() * group.length)];
    };

    // Returns [{item, count}] for each roll unlocked by the dice result (random items).
    // Roll 1 (≥7):  base 2, max 6
    // Roll 2 (≥8):  base 2, max 5
    // Roll 3 (≥10): base 1, max 5
    // Roll 4 (≥12): base 1, max 3
    // Roll 5 (≥15, rarity 2+): base 1, max 3
    // Roll 6 (≥18, rarity 2+): base 1, max 3
    const addRoll = function (rolls, result, table, threshold, base, cap) {
        if (result < threshold) return;
        const item = pickFromTable(table);
        if (item == null) return;
        rolls.push({ item: item, count: Math.min(base + (result - threshold), cap) });
    };

    const resolveLoot = function (result, tables) {
        let rolls = [];
        addRoll(rolls, result, tables.allRarities, 7,  2, 6);
        rolls = rolls.concat(resolveExtraLoot(result, tables));
        return rolls;
    };

    // Returns the count of the specific chosen item from roll 1.
    // Threshold = 7 + ceil(rarity * 1.5), base 2, cap 4 (max 6 total). Returns 0 if below threshold.
    const resolveSpecificItemCount = function (result, item) {
        const threshold = 6 + Math.ceil((item.rarity || 1) * (item.rarity || 1) * 0.77);
        if (result < threshold) return 0;
        return Math.min(2 + (result - threshold), 6);
    };

    // Returns [{item, count}] for rolls 2-6 only (random items from the table).
    const resolveExtraLoot = function (result, tables) {
        const rolls = [];
        addRoll(rolls, result, tables.allRarities, 8,  1, 5);
        addRoll(rolls, result, tables.allRarities, 11, 1, 5);
        addRoll(rolls, result, tables.allRarities, 13, 1, 3);
        addRoll(rolls, result, tables.rarity2Plus, 16, 1, 3);
        addRoll(rolls, result, tables.rarity2Plus, 19, 1, 3);
        return rolls;
    };

    // ─── Location Lookup ────────────────────────────────────────────────────────

    // Returns { locationDef, items } or null if the location/filter is invalid.
    const getLocationData = function (locationTitle) {
        const locationTypes = WuxDef.Filter(new DatabaseFilterData("group", "LocationType"));
        let locationDef = null;
        for (let i = 0; i < locationTypes.length; i++) {
            if (locationTypes[i].title.toLowerCase() === locationTitle.trim().toLowerCase()) {
                locationDef = locationTypes[i];
                break;
            }
        }
        if (locationDef == null) return null;

        const desc = locationDef.getDescription("");
        let filterValues = [];
        const match = desc.match(/location:([^|;]+)/);
        if (match) {
            filterValues = match[1].split(",").map(function (s) { return s.trim(); }).filter(function (s) { return s !== ""; });
        }
        if (filterValues.length === 0) return null;

        const items = WuxGoods.Filter([new DatabaseFilterData("location", filterValues)]);
        return { locationDef: locationDef, items: items };
    };

    // ─── Repeating Section Goods ─────────────────────────────────────────────────

    const getGearField = function (attributeKey) {
        return WuxDef.Get("Gear").getVariable("-" + WuxDef.GetVariable(attributeKey));
    };

    // Finds an existing character attribute or creates it, then sets its current value.
    const setCharacterAttribute = function (charId, attrName, value) {
        const attr = findObjs({ _characterid: charId, _type: "attribute", name: attrName })[0];
        if (attr) {
            attr.set("current", value);
        } else {
            createObj("attribute", { _characterid: charId, name: attrName, current: value });
        }
    };

    const addItemsToSection = function (charId, itemCounts, sectionName, mainGroup) {
        const repeater      = new SandboxRepeatingSectionHandler(sectionName, charId);
        const nameField     = getGearField("ItemName");
        const countField    = getGearField("ItemCount");
        const visibleField  = getGearField("ItemIsVisible");
        const groupField    = getGearField("ItemMainGroup");
        const itemGroupField= getGearField("ItemGroup");
        const bulkField     = getGearField("ItemBulk");
        const subGroupField = getGearField("ItemSubGroup");
        const buyInfoField  = WuxDef.GetVariable("Gear_Buy", WuxDef._info);
        const buyBulkInfoField = WuxDef.GetVariable("Gear_BuyBulk", WuxDef._info);
        const prefix        = `${repeater.repeatingSection}_`;
        const nameSuffix    = `_${nameField}`;

        // Find existing rows and map itemName → rowId.
        const existingRowIds = {};
        findObjs({ _characterid: charId, _type: "attribute" })
            .forEach(function (a) {
                const n = a.get("name");
                if (n.startsWith(prefix) && n.endsWith(nameSuffix)) {
                    const rowId = n.slice(prefix.length, n.length - nameSuffix.length);
                    existingRowIds[a.get("current")] = rowId;
                }
            });

        Object.keys(itemCounts).forEach(function (itemName) {
            const count = itemCounts[itemName];
            const item  = WuxGoods.Get(itemName);
            const itemValue = item != undefined ? (parseInt(item.value) || 0) : 0;
            const buyLabel     = WuxDef.Get("Gear_Buy").getTitle(`5 (${itemValue}J)`);
            const buyBulkLabel = WuxDef.Get("Gear_BuyBulk").getTitle(`50 (${itemValue * 10}J)`);

            if (existingRowIds[itemName] !== undefined) {
                const rowId       = existingRowIds[itemName];
                const countAttrName = `${prefix}${rowId}_${countField}`;
                const countAttr   = findObjs({ _characterid: charId, _type: "attribute", name: countAttrName })[0];
                if (countAttr) {
                    const current = parseInt(countAttr.get("current")) || 0;
                    countAttr.set("current", current + count);
                }
            } else {
                const rowId       = repeater.generateRowId();
                const itemGroup   = item != undefined ? (item.group    || "") : "";
                const itemBulk    = item != undefined ? (item.bulk     || "") : "";
                const itemCategory= item != undefined ? (item.category || "") : "";
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${nameField}`,        current: itemName });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${countField}`,       current: count });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${visibleField}`,     current: "on" });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${groupField}`,       current: mainGroup });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${itemGroupField}`,   current: itemGroup });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${bulkField}`,        current: itemBulk });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${subGroupField}`,    current: itemCategory });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${buyInfoField}`,     current: buyLabel });
                createObj("attribute", { _characterid: charId, name: `${prefix}${rowId}_${buyBulkInfoField}`, current: buyBulkLabel });
            }
        });

        // Flip the section's none-check so the sheet stops showing "empty".
        const noneCheckDef = sectionName === "RepeatingFoods" ? "Gear_FoodIsVisible" : "Gear_GearIsVisible";
        const noneCheckVar = WuxDef.GetVariable(noneCheckDef);
        const noneAttr = findObjs({ _characterid: charId, _type: "attribute", name: noneCheckVar })[0];
        if (noneAttr) {
            noneAttr.set("current", "on");
        } else {
            createObj("attribute", { _characterid: charId, name: noneCheckVar, current: "on" });
        }
    };

    const addGoodsToCharacter = function (charId, itemCounts) {
        addItemsToSection(charId, itemCounts, "RepeatingFoods", "Goods");
    };

    // Returns a character's current RepeatingFoods count for an item (0 if not present).
    const getFoodsItemCount = function (charId, itemName) {
        const nameField  = getGearField("ItemName");
        const countField = getGearField("ItemCount");
        const repeater    = new SandboxRepeatingSectionHandler("RepeatingFoods", charId);
        const prefix      = `${repeater.repeatingSection}_`;
        const nameSuffix  = `_${nameField}`;

        let count = 0;
        findObjs({ _characterid: charId, _type: "attribute" }).forEach(function (a) {
            const n = a.get("name");
            if (n.startsWith(prefix) && n.endsWith(nameSuffix) && a.get("current") === itemName) {
                const rowId = n.slice(prefix.length, n.length - nameSuffix.length);
                const countAttr = findObjs({ _characterid: charId, _type: "attribute", name: `${prefix}${rowId}_${countField}` })[0];
                if (countAttr) count = parseInt(countAttr.get("current")) || 0;
            }
        });
        return count;
    };

    const addAnimalGoodToCharacter = function (charId, itemCounts) {
        addItemsToSection(charId, itemCounts, "RepeatingGear", "Animal Good");
    };

    // Adds gathered items to a character, routing by group the same way Hunt does:
    // Animal Good and Material goods go to RepeatingGear, everything else to RepeatingFoods.
    const addGatheredItems = function (charId, itemCounts) {
        const foodItems = {};
        const gearItems = {};
        Object.keys(itemCounts).forEach(function (itemName) {
            const item  = WuxGoods.Get(itemName);
            const group = item ? item.group : "";
            if (group === "Animal Good" || group === "Material") {
                gearItems[itemName] = itemCounts[itemName];
            } else {
                foodItems[itemName] = itemCounts[itemName];
            }
        });
        if (Object.keys(foodItems).length > 0) addGoodsToCharacter(charId, foodItems);
        if (Object.keys(gearItems).length > 0) addAnimalGoodToCharacter(charId, gearItems);
    };

    // Creates a new RepeatingCooking row for an ingredient and returns its row id.
    const createCookingRow = function (charId, itemName, itemGroup) {
        const repeater        = new SandboxRepeatingSectionHandler("RepeatingCooking", charId);
        const nameField       = getGearField("ItemName");
        const countField      = getGearField("ItemCount");
        const visibleField    = getGearField("ItemIsVisible");
        const mainGroupField  = getGearField("ItemMainGroup");
        const itemGroupField  = getGearField("ItemGroup");
        const rowId           = repeater.generateRowId();
        const prefix          = `${repeater.repeatingSection}_${rowId}_`;

        createObj("attribute", { _characterid: charId, name: `${prefix}${nameField}`,      current: itemName });
        createObj("attribute", { _characterid: charId, name: `${prefix}${countField}`,     current: 1 });
        createObj("attribute", { _characterid: charId, name: `${prefix}${visibleField}`,   current: "on" });
        createObj("attribute", { _characterid: charId, name: `${prefix}${mainGroupField}`, current: "Goods" });
        createObj("attribute", { _characterid: charId, name: `${prefix}${itemGroupField}`, current: itemGroup });

        return rowId;
    };

    // Increments an existing RepeatingCooking row's count by 1 using its cached row id.
    const incrementCookingRowCount = function (charId, rowId) {
        if (rowId === undefined) return;
        const repeater       = new SandboxRepeatingSectionHandler("RepeatingCooking", charId);
        const countField     = getGearField("ItemCount");
        const countAttrName  = `${repeater.repeatingSection}_${rowId}_${countField}`;
        const countAttr      = findObjs({ _characterid: charId, _type: "attribute", name: countAttrName })[0];
        if (countAttr) {
            const current = parseInt(countAttr.get("current")) || 0;
            countAttr.set("current", current + 1);
        }
    };

    // Decrements an existing RepeatingCooking row's count by 1 using its cached row id,
    // clamped to 0. Returns the resulting count (0 if the row/attribute doesn't exist).
    const decrementCookingRowCount = function (charId, rowId) {
        if (rowId === undefined) return 0;
        const repeater       = new SandboxRepeatingSectionHandler("RepeatingCooking", charId);
        const countField     = getGearField("ItemCount");
        const countAttrName  = `${repeater.repeatingSection}_${rowId}_${countField}`;
        const countAttr      = findObjs({ _characterid: charId, _type: "attribute", name: countAttrName })[0];
        if (!countAttr) return 0;
        const newCount = Math.max(0, (parseInt(countAttr.get("current")) || 0) - 1);
        countAttr.set("current", newCount);
        return newCount;
    };

    // Deletes every attribute belonging to a RepeatingCooking row using its cached row id.
    const deleteCookingRow = function (charId, rowId) {
        if (rowId === undefined) return;
        const repeater = new SandboxRepeatingSectionHandler("RepeatingCooking", charId);
        const prefix   = `${repeater.repeatingSection}_${rowId}_`;
        findObjs({ _characterid: charId, _type: "attribute" }).forEach(function (a) {
            if (a.get("name").startsWith(prefix)) {
                a.remove();
            }
        });
    };

    // Deletes every row in a character's RepeatingCooking section.
    const clearCookingRows = function (charId) {
        const repeater = new SandboxRepeatingSectionHandler("RepeatingCooking", charId);
        const prefix   = `${repeater.repeatingSection}_`;
        findObjs({ _characterid: charId, _type: "attribute" }).forEach(function (a) {
            if (a.get("name").startsWith(prefix)) {
                a.remove();
            }
        });
    };

    // ─── Notice Roll Runner ─────────────────────────────────────────────────────

    // Rolls Notice for each target, then calls onResult(result, noticeRoll, tokenTargetData).
    const runGatherCheck = function (targets, tables, onResult) {
        const noticeVar = WuxDef.GetVariable("Skill_Notice");
        _.each(targets, function (tokenTargetData) {
            const advantage  = tokenTargetData.getAdvantage();
            const dieRoll    = new DieRoll();
            dieRoll.rollCheck(advantage);
            const noticeRoll = new DieRoll(dieRoll);

            const attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
            attributeHandler.addMod(noticeVar);
            attributeHandler.addFinishCallback(function (attrHandler) {
                const noticeMod = attrHandler.parseInt(noticeVar, 0, false);
                noticeRoll.addModToRoll(noticeMod);
                onResult(noticeRoll.total, noticeRoll, tokenTargetData);
            });
            attributeHandler.run();
        });
    };

    // ─── Meal Helpers ───────────────────────────────────────────────────────────

    const getMeals = function () {
        return WuxItems.Filter([new DatabaseFilterData("group", ["Basic Meal", "Meal"])]);
    };

    // ─── Commands ───────────────────────────────────────────────────────────────

    var
        // !adventureoptions [location|||waterSource] — shows the Adventure Options window.
        // If location is provided, saves both values to state. If omitted, reads from state.
        commandAdventureOptions = function (msg, content) {
            const parts       = content ? content.split("|||") : [];
            const locationArg = parts[0] ? parts[0].trim() : "";
            const waterArg    = parts[1] ? parts[1].trim() : null;
            const isExplicit  = !!locationArg;

            const resolved     = isExplicit ? locationArg : (state.WuxAdventureState || {}).currentLocation || "";
            const waterSource  = waterArg !== null ? waterArg : (state.WuxAdventureState || {}).waterSource || "";

            if (!resolved) {
                sendChat("System", `/w "${msg.who}" No location is set. Use the location picker to set one first.`, null, { noarchive: true });
                return;
            }

            if (isExplicit) {
                state.WuxAdventureState.currentLocation = resolved;
                state.WuxAdventureState.waterSource     = waterSource;
            }

            const locationData = getLocationData(resolved);
            const outputLines  = [
                `Adventure Options`,
                `Current Environment: ${resolved}`,
                waterSource && waterSource !== "No Water" ? `Water Source: ${waterSource}` : "",
                `[Gather Materials (Any)](!gather ${resolved})`
            ].filter(function (l) { return l !== ""; });

            if (locationData != null && locationData.items.length > 0) {
                const itemOptions = locationData.items
                    .map(function (i) { return i.title || i.name; })
                    .join("|");
                outputLines.push(`[Gather Material](!gathermaterial ${resolved}@@@?{Choose Item|${itemOptions}})`);
            }

            outputLines.push(`[See All Materials](!seematerials)`);
            outputLines.push(`[Hunt](!hunt)`);
            if (waterSource && waterSource !== "No Water") {
                outputLines.push(`[Fish](!fish)`);
            }
            outputLines.push(`<div>&nbsp</div><div style='font-weight: bold'>Cooking</div>`);
            outputLines.push(`[View Cooking](!viewcooking)`);

            const messageObject = new SystemInfoMessage(outputLines);
            messageObject.setSender("Wuxing");
            if (isExplicit) {
                WuxMessage.Send(messageObject);
            } else {
                WuxMessage.SendToSender(messageObject, msg);
            }
        },

        // !gather <LocationTitle> — rolls Notice for each selected token and grants random loot.
        commandGather = function (msg, targets, locationTitle) {
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected for gathering.`, null, { noarchive: true });
                return;
            }
            const locationData = getLocationData(locationTitle);
            if (locationData == null) {
                sendChat("System", `/w GM Unknown location or no filter defined: "${locationTitle}".`, null, { noarchive: true });
                return;
            }
            if (locationData.items.length === 0) {
                sendChat("System", `/w GM No items found for location: ${locationData.locationDef.title}.`, null, { noarchive: true });
                return;
            }

            const tables = buildLootTables(locationData.items);
            runGatherCheck(targets, tables, function (result, noticeRoll, tokenTargetData) {
                const lootRolls  = resolveLoot(result, tables);
                const itemCounts = {};
                lootRolls.forEach(function (loot) {
                    itemCounts[loot.item.name] = (itemCounts[loot.item.name] || 0) + loot.count;
                });

                if (Object.keys(itemCounts).length > 0) {
                    addGatheredItems(tokenTargetData.charId, itemCounts);
                }

                const rollDisplay = Format.ShowTooltip(result.toString(), noticeRoll.message);
                const outputLines = [
                    `${tokenTargetData.displayName} — Gathering: ${locationData.locationDef.title}`,
                    `Notice Check: ${rollDisplay}`
                ];
                if (lootRolls.length === 0) {
                    outputLines.push(`No materials found (need 7+).`);
                } else {
                    outputLines.push(`Materials gathered:`);
                    lootRolls.forEach(function (loot) {
                        outputLines.push(`${loot.item.title || loot.item.name} x${loot.count}`);
                    });
                }

                const messageObject = new SystemInfoMessage(outputLines);
                messageObject.setSender(tokenTargetData.displayName || "Wuxing");
                WuxMessage.SendToSenderAndGM(messageObject, msg);
            });
        },

        // !gathermaterial <location>@@@<itemName> — rolls Notice for a specific item.
        // Roll 1 uses a rarity-based threshold and gives the chosen item; rolls 2-6 give random loot.
        commandGatherSpecific = function (msg, targets, locationTitle, itemName) {
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected for gathering.`, null, { noarchive: true });
                return;
            }
            const item = WuxGoods.Get(itemName);
            if (item == undefined) {
                sendChat("System", `/w GM Unknown item: "${itemName}".`, null, { noarchive: true });
                return;
            }
            const locationData = getLocationData(locationTitle);
            if (locationData == null) {
                sendChat("System", `/w GM Unknown location or no filter defined: "${locationTitle}".`, null, { noarchive: true });
                return;
            }

            const threshold   = 7 + Math.floor((item.rarity || 1) * 1.5);
            const tables      = buildLootTables(locationData.items);
            const itemDisplay = item.title || item.name;

            runGatherCheck(targets, tables, function (result, noticeRoll, tokenTargetData) {
                const specificCount = resolveSpecificItemCount(result, item);
                const extraRolls    = resolveExtraLoot(result, tables);

                const itemCounts = {};
                if (specificCount > 0) {
                    itemCounts[item.name] = specificCount;
                }
                extraRolls.forEach(function (loot) {
                    itemCounts[loot.item.name] = (itemCounts[loot.item.name] || 0) + loot.count;
                });

                if (Object.keys(itemCounts).length > 0) {
                    addGatheredItems(tokenTargetData.charId, itemCounts);
                }

                const rollDisplay = Format.ShowTooltip(result.toString(), noticeRoll.message);
                const outputLines = [
                    `${tokenTargetData.displayName} — Gathering: ${itemDisplay}`,
                    `Notice Check: ${rollDisplay} (need ${threshold}+)`
                ];
                if (specificCount === 0 && extraRolls.length === 0) {
                    outputLines.push(`No materials found (need ${threshold}+).`);
                } else {
                    if (specificCount > 0) {
                        outputLines.push(`${itemDisplay} x${specificCount}`);
                    }
                    extraRolls.forEach(function (loot) {
                        outputLines.push(`${loot.item.title || loot.item.name} x${loot.count}`);
                    });
                }

                const messageObject = new SystemInfoMessage(outputLines);
                messageObject.setSender(tokenTargetData.displayName || "Wuxing");
                WuxMessage.SendToSenderAndGM(messageObject, msg);
            });
        },

        // Applies a single meal's technique effects to one token's character sheet.
        applyMealToToken = function (msg, tokenTargetData, meal, technique, isSavory) {
            const surgeVar = WuxDef.GetVariable("Surge");
            const attributeHandler = new SandboxAttributeHandler(tokenTargetData.charId);
            const mealLabel = isSavory ? `Savoury ${meal.name}` : meal.name;
            const outputLines = [`${tokenTargetData.displayName} enjoys a ${mealLabel}`];

            attributeHandler.addFinishCallback(function (attrHandler) {
                technique.effects.iterate(function (effect) {
                    if (effect.target === "Surge" && effect.type === "Heal") {
                        const base = parseInt(effect.dVal) || 0;
                        const bonus = effect.formula.getValue(attrHandler);
                        const healAmount = base + bonus;
                        if (healAmount > 0) {
                            const current = attrHandler.parseInt(surgeVar, 0, false);
                            const max = attrHandler.parseInt(surgeVar, 0, true);
                            const newValue = Math.min(current + healAmount, max);
                            attrHandler.addUpdate(surgeVar, newValue);
                            const breakdown = bonus > 0 ? `${base} + ${bonus}` : `${base}`;
                            outputLines.push(`${tokenTargetData.displayName} gains ${Format.ShowTooltip(healAmount, breakdown)} Surge`);
                        }
                    } else if (effect.target === "Status" && effect.type === "Add") {
                        const defName = Format.GetDefinitionName("Status", effect.effect);
                        const statusDef = WuxDef.Get(defName);
                        if (statusDef && statusDef.presetStatus) {
                            if (statusDef.hasRanks) {
                                const rank = parseInt(effect.dVal) || 1;
                                attrHandler.addUpdate(statusDef.getVariable(), rank);
                                outputLines.push(`${tokenTargetData.displayName} gains ${statusDef.getTitle()} ${rank}`);
                            } else {
                                attrHandler.addUpdate(statusDef.getVariable(), "on");
                                outputLines.push(`${tokenTargetData.displayName} gains ${statusDef.getTitle()}`);
                            }
                        }
                    } else if (effect.target === "Status" && effect.type === "Remove") {
                        const defName = Format.GetDefinitionName("Status", effect.effect);
                        const statusDef = WuxDef.Get(defName);
                        if (statusDef && statusDef.presetStatus) {
                            attrHandler.addUpdate(statusDef.getVariable(), statusDef.hasRanks ? 0 : "");
                            outputLines.push(`${tokenTargetData.displayName} loses ${statusDef.getTitle()}`);
                        }
                    }
                });

                if (isSavory) {
                    const savorVar = WuxDef.GetVariable("Boon_Savor");
                    attrHandler.addUpdate(savorVar, "on");
                    outputLines.push(`${tokenTargetData.displayName} gains Savoury Boon`);
                }

                const messageObject = new SystemInfoMessage(outputLines);
                messageObject.setSender(tokenTargetData.displayName || "Wuxing");
                WuxMessage.SendToSenderAndGM(messageObject, msg);
            });

            attributeHandler.run();
        },

        // !givemeal <mealName>[|||savoury] — feeds a meal to each selected token.
        // If "savoury" is appended, also applies the Savoury Boon to each character.
        commandGiveMeal = function (msg, targets, content) {
            const parts    = content.split("|||");
            const mealName = parts[0] ? parts[0].trim() : "";
            const isSavory = parts[1] ? parts[1].trim().toLowerCase() === "savoury" : false;

            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected.`, null, { noarchive: true });
                return;
            }
            const meal = WuxItems.Get(mealName);
            if (meal == undefined) {
                sendChat("System", `/w GM Unknown meal: "${mealName}".`, null, { noarchive: true });
                return;
            }
            const technique = WuxTechs.Get(mealName);
            if (technique == undefined) {
                sendChat("System", `/w GM No technique found for meal: "${mealName}".`, null, { noarchive: true });
                return;
            }
            targets.forEach(function (tokenTargetData) {
                applyMealToToken(msg, tokenTargetData, meal, technique, isSavory);
            });
        },

        // ─── Cooking Event ───────────────────────────────────────────────────────────

        cookingSchemaVersion = "0.2.0",
        adventureSchemaVersion = "0.2.0",

        checkInstall = function () {
            if (!state.hasOwnProperty("WuxCookingEvent") || state.WuxCookingEvent.version !== cookingSchemaVersion) {
                state.WuxCookingEvent = {
                    version: cookingSchemaVersion,
                    active: false,
                    initiatorName: "",
                    ingredients: {},
                    tokens: {}
                };
            }
            if (!state.hasOwnProperty("WuxAdventureState") || state.WuxAdventureState.version !== adventureSchemaVersion) {
                state.WuxAdventureState = {
                    version: adventureSchemaVersion,
                    currentLocation: "",
                    waterSource: ""
                };
            }
        },

        // Removes items from a character's RepeatingFoods section.
        // itemCounts: { "Item Name": quantityToRemove, ... }
        deductGoodsFromCharacter = function (charId, itemCounts) {
            const nameField  = getGearField("ItemName");
            const countField = getGearField("ItemCount");
            const repeater   = new SandboxRepeatingSectionHandler("RepeatingFoods", charId);
            const prefix     = `${repeater.repeatingSection}_`;
            const nameSuffix = `_${nameField}`;

            const existingRowIds = {};
            findObjs({ _characterid: charId, _type: "attribute" })
                .forEach(function (a) {
                    const n = a.get("name");
                    if (n.startsWith(prefix) && n.endsWith(nameSuffix)) {
                        const rowId = n.slice(prefix.length, n.length - nameSuffix.length);
                        existingRowIds[a.get("current")] = rowId;
                    }
                });

            Object.keys(itemCounts).forEach(function (itemName) {
                const rowId = existingRowIds[itemName];
                if (rowId === undefined) return;
                const countAttrName = `${prefix}${rowId}_${countField}`;
                const countAttr = findObjs({ _characterid: charId, _type: "attribute", name: countAttrName })[0];
                if (countAttr) {
                    const current = parseInt(countAttr.get("current")) || 0;
                    countAttr.set("current", Math.max(0, current - itemCounts[itemName]));
                }
            });
        },

        // Returns a formatted ingredient list string for display. If viewerCharName is
        // given, that contributor's own name is shown as "You" instead of their name.
        formatIngredientList = function (viewerCharName) {
            const ingredients = state.WuxCookingEvent.ingredients;
            const entries = Object.values(ingredients);
            if (entries.length === 0) return "No ingredients";

            const groups = {};
            entries.forEach(function (ing) {
                const group = (WuxGoods.Get(ing.name) || {}).group || "Other";
                if (!groups[group]) groups[group] = [];
                groups[group].push(ing);
            });

            const groupNames = Object.keys(groups).sort();
            const sections = [];
            groupNames.forEach(function (group) {
                const ings = groups[group].sort(function (a, b) { return a.name.localeCompare(b.name); });
                const total = ings.reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
                const lines = [`[${group}] (${total})`];
                ings.forEach(function (ing) {
                    const contributorName = viewerCharName != undefined && ing.charName === viewerCharName
                        ? "You" : ing.charName;
                    const entry = ing.quantity > 1
                        ? `${ing.name} x${ing.quantity} (${contributorName})`
                        : `${ing.name} (${contributorName})`;
                    lines.push(`  ${entry}`);
                });
                sections.push(lines.join("\n"));
            });
            return sections.join("\n\n");
        },

        // Returns the recipe name the cooking event currently predicts, defaulting to
        // Tasty Meal when there aren't enough ingredients contributed yet to predict one.
        getCurrentRecipeName = function () {
            const ingredients   = state.WuxCookingEvent.ingredients;
            const totalQuantity = Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
            return totalQuantity > 0 ? predictMeal(ingredients) : "Tasty Meal";
        },

        // Returns the "Feeds: X (Y ingredients)" text for the cooking event's current ingredients.
        getFeedsText = function () {
            const ingredients   = state.WuxCookingEvent.ingredients;
            const totalQuantity = Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
            const feeds         = Math.floor(totalQuantity / 5);
            return `Feeds: ${feeds} (${totalQuantity} ingredient${totalQuantity !== 1 ? "s" : ""})`;
        },

        // Returns the feeds text plus how many people are involved in the cooking event
        // and a reminder of how many more meals are needed for everyone to eat.
        getMealCountText = function () {
            const ingredients      = state.WuxCookingEvent.ingredients;
            const totalQuantity    = Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
            const feeds            = Math.floor(totalQuantity / 5);
            const remainder        = totalQuantity % 5;
            const neededForNext    = remainder === 0 ? 5 : 5 - remainder;
            const participantCount = Object.keys(state.WuxCookingEvent.tokens).length;
            const stillNeeded      = Math.max(0, participantCount - feeds);

            return [
                getFeedsText(),
                `${neededForNext} more ingredient${neededForNext !== 1 ? "s" : ""} needed for another meal.`,
                "",
                `${participantCount} ${participantCount === 1 ? "person is" : "people are"} involved in this cooking event.`,
                stillNeeded > 0
                    ? `You need ${stillNeeded} more meal${stillNeeded !== 1 ? "s" : ""} for everyone to eat.`
                    : `You have enough meals for everyone to eat.`
            ].join("\n");
        },

        // Writes the current recipe (name + description) to a participating token's character sheet.
        applyActiveRecipeToToken = function (tokenTargetData) {
            const recipeName = getCurrentRecipeName();
            const recipeItem = WuxItems.Get(recipeName);
            const description = recipeItem && recipeItem.description ? recipeItem.description : "";

            const activeRecipeVar     = WuxDef.GetVariable("Gear_ActiveRecipe");
            const activeRecipeInfoVar = WuxDef.GetVariable("Gear_ActiveRecipe", WuxDef._info);

            setCharacterAttribute(tokenTargetData.charId, activeRecipeVar, recipeName);
            setCharacterAttribute(tokenTargetData.charId, activeRecipeInfoVar, description);
        },

        // Clears a participant's RepeatingCooking rows and empties the Active Meal data
        // (Gear_ActiveRecipe back to "0") so the Cooking Events section hides again.
        clearCookingDataForToken = function (participant) {
            clearCookingRows(participant.charId);

            const activeRecipeVar     = WuxDef.GetVariable("Gear_ActiveRecipe");
            const activeRecipeInfoVar = WuxDef.GetVariable("Gear_ActiveRecipe", WuxDef._info);

            setCharacterAttribute(participant.charId, activeRecipeVar, "0");
            setCharacterAttribute(participant.charId, activeRecipeInfoVar, "");
            setCharacterAttribute(participant.charId, WuxDef.GetVariable("Gear_CookingIsVisible"), "0");
        },

        // Shows/hides a character's RepeatingCooking rows (vs. a "None" placeholder)
        // depending on whether they currently have any contributed ingredients.
        updateCookingVisibility = function (charId) {
            const hasContributions = Object.values(state.WuxCookingEvent.ingredients)
                .some(function (ing) { return ing.charId === charId; });
            setCharacterAttribute(charId, WuxDef.GetVariable("Gear_CookingIsVisible"), hasContributions ? "on" : "0");
        },

        // Pushes the current predicted recipe (if changed), the meal count, and each
        // participant's personalized ingredient list to every character in the cooking event.
        broadcastCookingUpdate = function (recipeChanged) {
            const activeIngredientListVar = WuxDef.GetVariable("Gear_ActiveIngredientList");
            const mealCountVar            = WuxDef.GetVariable("Gear_MealCount");
            const mealCountText            = getMealCountText();
            Object.values(state.WuxCookingEvent.tokens).forEach(function (participant) {
                if (recipeChanged) {
                    applyActiveRecipeToToken(participant);
                }
                setCharacterAttribute(participant.charId, activeIngredientListVar, formatIngredientList(participant.charName));
                setCharacterAttribute(participant.charId, mealCountVar, mealCountText);
                updateCookingVisibility(participant.charId);
            });
        },

        // Returns a character's Cook skill value.
        getCookSkillValue = function (charId) {
            const cookSkillVar = WuxDef.GetVariable("Skill_Cook");
            const attributeHandler = new SandboxAttributeHandler(charId);
            attributeHandler.addMod(cookSkillVar);
            let cookMod = 0;
            attributeHandler.addFinishCallback(function (attrHandler) {
                cookMod = attrHandler.parseInt(cookSkillVar, 0, false);
            });
            attributeHandler.run();
            return cookMod;
        },

        // Writes each participant's Cook skill value to Gear_CookingScore, marking
        // whoever has the highest score (ties included) with "(You have the highest Cook skill)".
        updateCookingScores = function () {
            const participants = Object.values(state.WuxCookingEvent.tokens);
            if (participants.length === 0) return;

            const scores = participants.map(function (participant) {
                return { participant: participant, score: getCookSkillValue(participant.charId) };
            });
            const bestScore = scores.reduce(function (max, s) { return Math.max(max, s.score); }, -Infinity);

            const cookingScoreVar = WuxDef.GetVariable("Gear_CookingScore");
            scores.forEach(function (s) {
                const label = s.score === bestScore ? `${s.score} (You have the highest Cook skill)` : `${s.score}`;
                setCharacterAttribute(s.participant.charId, cookingScoreVar, label);
            });
        },

        commandViewCooking = function (msg) {
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w "${msg.who}" No cooking event is in progress.`, null, { noarchive: true });
                return;
            }
            const ingredients   = state.WuxCookingEvent.ingredients;
            const hasIngredients = Object.keys(ingredients).length > 0;
            const totalQuantity = hasIngredients
                ? Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0)
                : 0;
            const predicted     = hasIngredients ? predictMeal(ingredients) : null;
            const predictedItem = predicted ? WuxItems.Get(predicted) : null;

            const outputLines   = [
                predicted ? `Recipe: ${predicted}` : "",
                predictedItem && predictedItem.description ? predictedItem.description : "",
                `-------------------`,
                `Cooking contributions:`,
                hasIngredients ? formatIngredientList() : "No ingredients contributed yet.",
                `-------------------`,
                getMealCountText(),
                `[View Recipes](!viewrecipes)`,
                totalQuantity >= 5 ? `[Cook](!cook)` : ""
            ].filter(function (l) { return l !== ""; });
            const messageObject = new SystemInfoMessage(outputLines);
            messageObject.setSender("Wuxing");
            WuxMessage.SendToSender(messageObject, msg);
        },

        commandEndCooking = function (msg) {
            if (!playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can end a cooking event.`, null, { noarchive: true });
                return;
            }
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w GM No cooking event is in progress.`, null, { noarchive: true });
                return;
            }

            // Return every contributed ingredient to its owner's RepeatingFoods, as if each had been deleted.
            const returnByChar = {};
            Object.values(state.WuxCookingEvent.ingredients).forEach(function (ing) {
                if (!returnByChar[ing.charId]) returnByChar[ing.charId] = {};
                returnByChar[ing.charId][ing.name] = (returnByChar[ing.charId][ing.name] || 0) + ing.quantity;
            });
            Object.keys(returnByChar).forEach(function (charId) {
                addGoodsToCharacter(charId, returnByChar[charId]);
            });

            // Clear RepeatingCooking and reset the Active Recipe for every participant.
            Object.values(state.WuxCookingEvent.tokens).forEach(function (participant) {
                clearCookingDataForToken(participant);
            });

            state.WuxCookingEvent.active = false;
            state.WuxCookingEvent.initiatorName = "";
            state.WuxCookingEvent.ingredients = {};
            state.WuxCookingEvent.tokens = {};
            sendChat("System", `/w GM Cooking event ended. Ingredients cleared.`, null, { noarchive: true });
        },

        formatNameList = function (names) {
            if (names.length === 1) return names[0];
            if (names.length === 2) return `${names[0]} and ${names[1]}`;
            return `${names.slice(0, -1).join(", ")}, and ${names[names.length - 1]}`;
        },

        commandSeeMaterials = function (msg) {
            const foodGroups    = ["Compound", "Fruit", "Protein", "Starch", "Sugar", "Supplement", "Vegetable"];
            const currentLocation = (state.WuxAdventureState || {}).currentLocation || "";
            const locationData    = currentLocation ? getLocationData(currentLocation) : null;
            const items           = locationData ? locationData.items.filter(function (item) {
                return foodGroups.indexOf(item.group) !== -1;
            }) : WuxGoods.Filter([new DatabaseFilterData("group", foodGroups)]);

            const grouped = {};
            foodGroups.forEach(function (g) { grouped[g] = []; });
            items.forEach(function (item) {
                if (grouped[item.group]) grouped[item.group].push(item);
            });

            const sections = foodGroups
                .filter(function (g) { return grouped[g].length > 0; })
                .map(function (g) {
                    const sorted  = grouped[g].sort(function (a, b) { return a.name.localeCompare(b.name); });
                    const recipes = WuxItems.Filter([new DatabaseFilterData("goodsComponents", g)]);
                    const recipeList = recipes.length > 0
                        ? `Used in Recipes: ${formatNameList(recipes.map(function (r) { return r.name; }))}`
                        : "";
                    const lines   = [`[${g}]`];
                    sorted.forEach(function (item) {
                        const suffix = recipeList ? ` — ${recipeList}` : "";
                        lines.push(`  ${item.name}${suffix}`);
                    });
                    return lines.join("\n");
                });

            const outputLines = [
                "Available Materials",
                sections.join("\n\n")
            ];
            const messageObject = new SystemInfoMessage(outputLines);
            messageObject.setSender("Wuxing");
            WuxMessage.SendToSender(messageObject, msg);
        },

        // !hunt — GM only. Rolls Notice (DC 7) then the best Athletic skill (DC 10) for each
        // selected token. On success picks a random AnimalType, rolls a loot table 3+2+1 times
        // (plus 1 per point over 10), and adds Protein items to RepeatingFoods and Animal Good
        // items to RepeatingGear.
        commandHunt = function (msg) {
            if (!playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can initiate a hunt.`, null, { noarchive: true });
                return;
            }
            const targets = TokenReference.GetTokenTargetDataArray(msg);
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected.`, null, { noarchive: true });
                return;
            }

            const animalTypes = WuxDef.Filter([new DatabaseFilterData("group", "AnimalType")]);
            if (animalTypes.length === 0) {
                sendChat("System", `/w GM No AnimalType definitions found.`, null, { noarchive: true });
                return;
            }

            const noticeVar    = WuxDef.GetVariable("Skill_Notice");
            const athleticDefs = WuxDef.Filter([new DatabaseFilterData("subGroup", "Athletics")]);

            _.each(targets, function (tokenTargetData) {
                const advantage = tokenTargetData.getAdvantage();

                const noticeDie   = new DieRoll();
                noticeDie.rollCheck(advantage);
                const athleticDie = new DieRoll();
                athleticDie.rollCheck(advantage);

                const attrHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                attrHandler.addMod(noticeVar);
                athleticDefs.forEach(function (skillDef) {
                    attrHandler.addMod(WuxDef.GetVariable(skillDef.name));
                });

                attrHandler.addFinishCallback(function (handler) {
                    const noticeMod   = handler.parseInt(noticeVar, 0, false);
                    noticeDie.addModToRoll(noticeMod);
                    const noticeTotal = noticeDie.total;
                    const noticeDisp  = Format.ShowTooltip(noticeTotal.toString(), noticeDie.message);

                    if (noticeTotal < 7) {
                        const out = new SystemInfoMessage([
                            `${tokenTargetData.displayName} — Hunting`,
                            `Notice Check: ${noticeDisp}`,
                            `No creatures found.`
                        ]);
                        out.setSender(tokenTargetData.displayName || "Wuxing");
                        WuxMessage.SendToSenderAndGM(out, msg);
                        return;
                    }

                    // Pick the athletic skill with the highest modifier.
                    let bestMod  = -Infinity;
                    let bestDef  = null;
                    athleticDefs.forEach(function (skillDef) {
                        const mod = handler.parseInt(WuxDef.GetVariable(skillDef.name), 0, false);
                        if (mod > bestMod) { bestMod = mod; bestDef = skillDef; }
                    });

                    athleticDie.addModToRoll(bestMod);
                    const athleticTotal = athleticDie.total;
                    const skillName     = bestDef ? bestDef.title : "Athletics";
                    const athleticDisp  = Format.ShowTooltip(athleticTotal.toString(), athleticDie.message);

                    if (athleticTotal < 10) {
                        const out = new SystemInfoMessage([
                            `${tokenTargetData.displayName} — Hunting`,
                            `Notice Check: ${noticeDisp}`,
                            `${skillName} Check: ${athleticDisp}`,
                            `Failed Hunt.`
                        ]);
                        out.setSender(tokenTargetData.displayName || "Wuxing");
                        WuxMessage.SendToSenderAndGM(out, msg);
                        return;
                    }

                    // Pick a random animal type and get its goods.
                    const animalDef    = animalTypes[Math.floor(Math.random() * animalTypes.length)];
                    const desc         = animalDef.getDescription("");
                    const locMatch     = desc.match(/location:([^|;]+)/);
                    const filterValues = locMatch
                        ? locMatch[1].split(",").map(function (s) { return s.trim(); }).filter(Boolean)
                        : [];
                    const animalGoods  = filterValues.length > 0
                        ? WuxGoods.Filter([new DatabaseFilterData("location", filterValues)])
                        : [];

                    if (animalGoods.length === 0) {
                        const out = new SystemInfoMessage([
                            `${tokenTargetData.displayName} — Hunting`,
                            `Notice Check: ${noticeDisp}`,
                            `${skillName} Check: ${athleticDisp}`,
                            `No loot items defined for ${animalDef.title}.`
                        ]);
                        out.setSender(tokenTargetData.displayName || "Wuxing");
                        WuxMessage.SendToSenderAndGM(out, msg);
                        return;
                    }

                    const pickItem = function () {
                        return animalGoods[Math.floor(Math.random() * animalGoods.length)];
                    };

                    // Roll 3 times granting 3, 2, 1. Each point over 10 = 1 bonus roll.
                    const itemCounts = {};
                    const addLoot = function (item, count) {
                        itemCounts[item.name] = (itemCounts[item.name] || 0) + count;
                    };
                    addLoot(pickItem(), 3);
                    addLoot(pickItem(), 2);
                    addLoot(pickItem(), 1);
                    const bonusRolls = athleticTotal - 10;
                    for (let i = 0; i < bonusRolls; i++) {
                        addLoot(pickItem(), 1);
                    }

                    // Route items by group to the correct repeating section.
                    const foodItems = {};
                    const gearItems = {};
                    Object.keys(itemCounts).forEach(function (itemName) {
                        const item  = WuxGoods.Get(itemName);
                        const group = item ? item.group : "";
                        if (group === "Protein") {
                            foodItems[itemName] = itemCounts[itemName];
                        } else if (group === "Animal Good") {
                            gearItems[itemName] = itemCounts[itemName];
                        }
                    });
                    if (Object.keys(foodItems).length > 0) addGoodsToCharacter(tokenTargetData.charId, foodItems);
                    if (Object.keys(gearItems).length > 0) addAnimalGoodToCharacter(tokenTargetData.charId, gearItems);

                    const outputLines = [
                        `${tokenTargetData.displayName} — Hunting: ${animalDef.title}`,
                        `Notice Check: ${noticeDisp}`,
                        `${skillName} Check: ${athleticDisp}`,
                        `Items obtained:`
                    ];
                    Object.keys(itemCounts).sort().forEach(function (itemName) {
                        const item    = WuxGoods.Get(itemName);
                        const display = item ? (item.title || item.name) : itemName;
                        outputLines.push(`  ${display} x${itemCounts[itemName]}`);
                    });

                    const out = new SystemInfoMessage(outputLines);
                    out.setSender(tokenTargetData.displayName || "Wuxing");
                    WuxMessage.SendToSenderAndGM(out, msg);
                });

                attrHandler.run();
            });
        },

        // !fish — GM only. Rolls the best Athletic skill (DC 8) for each selected token and
        // grants loot from items matching the current water source location. Requires a water
        // source to be set in state. The [Fish] button in Adventure Options is hidden when none
        // is set.
        commandFish = function (msg) {
            if (!playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can initiate fishing.`, null, { noarchive: true });
                return;
            }
            const targets = TokenReference.GetTokenTargetDataArray(msg);
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected.`, null, { noarchive: true });
                return;
            }

            const waterSource = (state.WuxAdventureState || {}).waterSource || "";
            if (!waterSource || waterSource === "No Water") {
                sendChat("System", `/w GM No water source is set.`, null, { noarchive: true });
                return;
            }

            const fishItems = WuxGoods.Filter([new DatabaseFilterData("location", [waterSource])]);
            if (fishItems.length === 0) {
                sendChat("System", `/w GM No items found for water source: ${waterSource}.`, null, { noarchive: true });
                return;
            }

            const tables        = buildLootTables(fishItems);
            const athleticDefs  = WuxDef.Filter([new DatabaseFilterData("subGroup", "Athletics")]);

            _.each(targets, function (tokenTargetData) {
                const advantage   = tokenTargetData.getAdvantage();
                const athleticDie = new DieRoll();
                athleticDie.rollCheck(advantage);

                const attrHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                athleticDefs.forEach(function (skillDef) {
                    attrHandler.addMod(WuxDef.GetVariable(skillDef.name));
                });

                attrHandler.addFinishCallback(function (handler) {
                    let bestMod = -Infinity;
                    let bestDef = null;
                    athleticDefs.forEach(function (skillDef) {
                        const mod = handler.parseInt(WuxDef.GetVariable(skillDef.name), 0, false);
                        if (mod > bestMod) { bestMod = mod; bestDef = skillDef; }
                    });

                    athleticDie.addModToRoll(bestMod);
                    const athleticTotal = athleticDie.total;
                    const skillName     = bestDef ? bestDef.title : "Athletics";
                    const athleticDisp  = Format.ShowTooltip(athleticTotal.toString(), athleticDie.message);

                    if (athleticTotal < 8) {
                        const out = new SystemInfoMessage([
                            `${tokenTargetData.displayName} — Fishing: ${waterSource}`,
                            `${skillName} Check: ${athleticDisp}`,
                            `No catch.`
                        ]);
                        out.setSender(tokenTargetData.displayName || "Wuxing");
                        WuxMessage.SendToSenderAndGM(out, msg);
                        return;
                    }

                    const rolls = [];
                    addRoll(rolls, athleticTotal, tables.allRarities, 8,  1, 3);
                    addRoll(rolls, athleticTotal, tables.allRarities, 10, 1, 2);
                    addRoll(rolls, athleticTotal, tables.allRarities, 12, 1, 2);
                    addRoll(rolls, athleticTotal, tables.allRarities, 14, 1, 2);

                    const itemCounts = {};
                    rolls.forEach(function (loot) {
                        itemCounts[loot.item.name] = (itemCounts[loot.item.name] || 0) + loot.count;
                    });

                    const foodItems = {};
                    const gearItems = {};
                    Object.keys(itemCounts).forEach(function (itemName) {
                        const item  = WuxGoods.Get(itemName);
                        const group = item ? item.group : "";
                        if (group === "Protein" || group === "Seafood") {
                            foodItems[itemName] = itemCounts[itemName];
                        } else if (group === "Animal Good") {
                            gearItems[itemName] = itemCounts[itemName];
                        }
                    });
                    if (Object.keys(foodItems).length > 0) addGoodsToCharacter(tokenTargetData.charId, foodItems);
                    if (Object.keys(gearItems).length > 0) addAnimalGoodToCharacter(tokenTargetData.charId, gearItems);

                    const outputLines = [
                        `${tokenTargetData.displayName} — Fishing: ${waterSource}`,
                        `${skillName} Check: ${athleticDisp}`,
                        `Items caught:`
                    ];
                    Object.keys(itemCounts).sort().forEach(function (itemName) {
                        const item    = WuxGoods.Get(itemName);
                        const display = item ? (item.title || item.name) : itemName;
                        outputLines.push(`  ${display} x${itemCounts[itemName]}`);
                    });

                    const out = new SystemInfoMessage(outputLines);
                    out.setSender(tokenTargetData.displayName || "Wuxing");
                    WuxMessage.SendToSenderAndGM(out, msg);
                });

                attrHandler.run();
            });
        },

        commandRest = function (msg) {
            if (!playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can call a rest.`, null, { noarchive: true });
                return;
            }
            const targets = TokenReference.GetTokenTargetDataArray(msg);
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected.`, null, { noarchive: true });
                return;
            }

            const surgeVar     = WuxDef.GetVariable("Surge");
            const exhaustedDef = WuxDef.Get("Stat_Exhausted");
            const restBoonVar  = WuxDef.GetVariable("Boon_Rest");

            const results = new Array(targets.length);
            let pending   = targets.length;

            targets.forEach(function (tokenTargetData, index) {
                const attrHandler = new SandboxAttributeHandler(tokenTargetData.charId);
                attrHandler.addFinishCallback(function (handler) {
                    const surgeMax = handler.parseInt(surgeVar, 0, true);
                    handler.addUpdate(surgeVar, surgeMax);
                    if (exhaustedDef && exhaustedDef.presetStatus) {
                        handler.addUpdate(exhaustedDef.getVariable(), exhaustedDef.hasRanks ? 0 : "");
                    }
                    handler.addUpdate(restBoonVar, "on");

                    results[index] = { name: tokenTargetData.displayName, surgeMax: surgeMax };
                    pending--;

                    if (pending === 0) {
                        const nameList   = formatNameList(results.map(function (r) { return r.name; }));
                        const isSingle   = results.length === 1;
                        const outputLines = [
                            `${nameList} take${isSingle ? "s" : ""} a rest`
                        ];
                        results.forEach(function (r) {
                            outputLines.push(`${isSingle ? "" : `${r.name}: `}Surge restored to ${r.surgeMax}`);
                        });
                        outputLines.push("Exhaustion removed");
                        outputLines.push("Rest Boon granted");

                        const messageObject = new SystemInfoMessage(outputLines);
                        messageObject.setSender("Wuxing");
                        WuxMessage.SendToSenderAndGM(messageObject, msg);
                    }
                });
                attrHandler.run();
            });
        },

        formatComponentsForDisplay = function (componentsStr) {
            if (!componentsStr || componentsStr.trim() === "") return "5 Any";
            return componentsStr.split(";").map(function (part) {
                part = part.trim();
                if (!part) return "";
                const spaceIdx = part.indexOf(" ");
                const count    = part.substring(0, spaceIdx);
                const typeStr  = part.substring(spaceIdx + 1).trim();
                const display  = typeStr.indexOf("_") !== -1
                    ? typeStr.replace("_", " (") + ")"
                    : typeStr;
                return `${count} ${display}`;
            }).filter(Boolean).join(", ");
        },

        commandViewRecipes = function (msg) {
            const meals = getMeals();
            const sections = meals.map(function (meal) {
                const components = formatComponentsForDisplay(meal.components);
                const desc       = meal.description || "";
                return desc
                    ? `${meal.name}\n  ${desc}\n  Recipe: ${components}`
                    : `${meal.name}\n  Recipe: ${components}`;
            });
            const outputLines = [
                "Meal Recipes",
                sections.join("\n\n")
            ];
            const messageObject = new SystemInfoMessage(outputLines);
            messageObject.setSender("Wuxing");
            WuxMessage.SendToSender(messageObject, msg);
        },

        commandStartCooking = function (msg) {
            if (!playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can start a cooking event.`, null, { noarchive: true });
                return;
            }

            const targets = TokenReference.GetTokenTargetDataArray(msg);
            if (targets.length === 0) {
                sendChat("System", `/w GM No tokens selected. Select the tokens joining the cooking event first.`, null, { noarchive: true });
                return;
            }

            const wasActive = state.WuxCookingEvent.active;
            if (!wasActive) {
                state.WuxCookingEvent.active = true;
                state.WuxCookingEvent.initiatorName = msg.who;
                state.WuxCookingEvent.ingredients = {};
                state.WuxCookingEvent.tokens = {};
            }

            targets.forEach(function (tokenTargetData) {
                if (!state.WuxCookingEvent.tokens[tokenTargetData.charId]) {
                    state.WuxCookingEvent.tokens[tokenTargetData.charId] = {
                        charId: tokenTargetData.charId,
                        tokenId: tokenTargetData.tokenId,
                        charName: tokenTargetData.charName,
                        displayName: tokenTargetData.displayName
                    };
                }
                applyActiveRecipeToToken(tokenTargetData);
                updateCookingVisibility(tokenTargetData.charId);
                setCharacterAttribute(tokenTargetData.charId, WuxDef.GetVariable("Gear_ActiveIngredientList"), formatIngredientList(tokenTargetData.charName));
            });

            // Set once the full participant roster is known so the "people involved" count is accurate.
            const mealCountText = getMealCountText();
            Object.values(state.WuxCookingEvent.tokens).forEach(function (participant) {
                setCharacterAttribute(participant.charId, WuxDef.GetVariable("Gear_MealCount"), mealCountText);
            });

            updateCookingScores();

            const participantNames = Object.values(state.WuxCookingEvent.tokens)
                .map(function (t) { return t.displayName; });

            const outputLines = wasActive
                ? [
                    "Cooking Event Updated",
                    `Joined: ${formatNameList(targets.map(function (t) { return t.displayName; }))}`,
                    `Participants: ${formatNameList(participantNames)}`,
                    `[View Recipes](!viewrecipes)`
                ]
                : [
                    "Cooking Event Started",
                    `Participants: ${formatNameList(participantNames)}`,
                    `Add ingredients using your character sheet's Cook button on each item.`,
                    `When ready, use [Cook](!cook) to make the skill check.`,
                    `[View Recipes](!viewrecipes)`
                ];
            const messageObject = new SystemInfoMessage(outputLines);
            messageObject.setSender("Wuxing");
            WuxMessage.Send(messageObject);
        },

        // Content: "ingredientName|||inventoryCount|||charName"
        commandAddIngredient = function (msg, content) {
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w "${msg.who}" No cooking event is in progress.`, null, { noarchive: true });
                return;
            }
            const parts          = content.split("|||");
            const ingredientName = parts[0] ? parts[0].trim() : "";
            const inventoryCount = parts[1] ? (parseInt(parts[1].trim()) || 0) : 0;
            const charName       = parts[2] ? parts[2].trim() : msg.who;

            if (!ingredientName) {
                sendChat("System", `/w "${msg.who}" Invalid ingredient.`, null, { noarchive: true });
                return;
            }

            const characters = findObjs({ _type: "character", name: charName });
            if (characters.length === 0) {
                return;
            }
            const charId = characters[0].id;

            if (getFoodsItemCount(charId, ingredientName) <= 0) {
                return;
            }

            const key           = `${ingredientName}:::${charName}`;
            const ingredients   = state.WuxCookingEvent.ingredients;
            const previousRecipe = getCurrentRecipeName();

            deductGoodsFromCharacter(charId, { [ingredientName]: 1 });

            if (ingredients[key]) {
                ingredients[key].quantity += 1;
                incrementCookingRowCount(charId, ingredients[key].rowId);
            } else {
                const itemGroup = (WuxGoods.Get(ingredientName) || {}).group || "";
                const rowId = createCookingRow(charId, ingredientName, itemGroup);
                ingredients[key] = {
                    name: ingredientName,
                    charName: charName,
                    charId: charId,
                    quantity: 1,
                    inventoryCount: inventoryCount,
                    rowId: rowId
                };
            }

            const recipeChanged = getCurrentRecipeName() !== previousRecipe;
            broadcastCookingUpdate(recipeChanged);
        },

        // Content: "ingredientName|||charName"
        commandRemoveIngredient = function (msg, content) {
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w "${msg.who}" No cooking event is in progress.`, null, { noarchive: true });
                return;
            }
            const parts          = content.split("|||");
            const ingredientName = parts[0] ? parts[0].trim() : "";
            const charName       = parts[1] ? parts[1].trim() : msg.who;

            if (!ingredientName) {
                sendChat("System", `/w "${msg.who}" Invalid ingredient.`, null, { noarchive: true });
                return;
            }

            const characters = findObjs({ _type: "character", name: charName });
            if (characters.length === 0) {
                return;
            }
            const charId = characters[0].id;

            const key         = `${ingredientName}:::${charName}`;
            const ingredients = state.WuxCookingEvent.ingredients;
            const ingredient  = ingredients[key];
            if (!ingredient) {
                return;
            }

            const previousRecipe = getCurrentRecipeName();

            ingredient.quantity -= 1;
            decrementCookingRowCount(charId, ingredient.rowId);

            if (ingredient.quantity <= 0) {
                deleteCookingRow(charId, ingredient.rowId);
                delete ingredients[key];
            }

            addGoodsToCharacter(charId, { [ingredientName]: 1 });

            const recipeChanged = getCurrentRecipeName() !== previousRecipe;
            broadcastCookingUpdate(recipeChanged);
        },

        // Content: "ingredientName|||charName"
        // Removes an ingredient's entire contributed quantity from the cooking event and
        // returns all of it to the character's RepeatingFoods.
        commandDeleteIngredient = function (msg, content) {
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w "${msg.who}" No cooking event is in progress.`, null, { noarchive: true });
                return;
            }
            const parts          = content.split("|||");
            const ingredientName = parts[0] ? parts[0].trim() : "";
            const charName       = parts[1] ? parts[1].trim() : msg.who;

            if (!ingredientName) {
                sendChat("System", `/w "${msg.who}" Invalid ingredient.`, null, { noarchive: true });
                return;
            }

            const characters = findObjs({ _type: "character", name: charName });
            if (characters.length === 0) {
                return;
            }
            const charId = characters[0].id;

            const key         = `${ingredientName}:::${charName}`;
            const ingredients = state.WuxCookingEvent.ingredients;
            const ingredient  = ingredients[key];
            if (!ingredient) {
                return;
            }

            const previousRecipe = getCurrentRecipeName();
            const removedQuantity = ingredient.quantity;

            deleteCookingRow(charId, ingredient.rowId);
            delete ingredients[key];

            addGoodsToCharacter(charId, { [ingredientName]: removedQuantity });

            const recipeChanged = getCurrentRecipeName() !== previousRecipe;
            broadcastCookingUpdate(recipeChanged);
        },

        parseComponentRequirements = function (componentsStr) {
            const requirements = {};
            componentsStr.split(";").forEach(function (part) {
                part = part.trim();
                if (!part) return;
                const spaceIdx = part.indexOf(" ");
                const count    = parseInt(part.substring(0, spaceIdx));
                const typeStr  = part.substring(spaceIdx + 1).trim();
                // "Supplement_Energy" → "Supplement:Energy"
                const typeKey  = typeStr.indexOf("_") !== -1 ? typeStr.replace("_", ":") : typeStr;
                requirements[typeKey] = (requirements[typeKey] || 0) + count;
            });
            return requirements;
        },

        buildIngredientTypeCounts = function (ingredients) {
            const counts = {};
            Object.values(ingredients).forEach(function (ing) {
                const goods = WuxGoods.Get(ing.name);
                if (goods && goods.group && goods.group !== "") {
                    // Count by plain group (e.g. "Supplement")
                    counts[goods.group] = (counts[goods.group] || 0) + ing.quantity;
                    // Also count by group:category for subcategory requirements
                    if (goods.category && goods.category !== "") {
                        const subKey = `${goods.group}:${goods.category}`;
                        counts[subKey] = (counts[subKey] || 0) + ing.quantity;
                    }
                }
            });
            return counts;
        },

        matchesMealRecipe = function (typeCounts, totalQuantity, requirements) {
            for (const typeKey in requirements) {
                if (typeKey === "Any") continue;
                const required = requirements[typeKey];
                const actual   = typeCounts[typeKey] || 0;
                if (actual * 5 < required * totalQuantity) return false;
            }
            return true;
        },

        predictMeal = function (ingredients) {
            const totalQuantity = Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
            if (totalQuantity === 0) return "No ingredients";
            const typeCounts = buildIngredientTypeCounts(ingredients);
            const meals = getMeals();
            for (let i = 0; i < meals.length; i++) {
                const m = meals[i];
                if (m.name === "Bland Meal" || m.name === "Tasty Meal") continue;
                if (!m.components || m.components.trim() === "" || m.components.trim() === "5 Any") continue;
                const recipe = parseComponentRequirements(m.components);
                if (matchesMealRecipe(typeCounts, totalQuantity, recipe)) return m.name;
            }
            return "Tasty Meal";
        },

        // Content (optional): a character name — used by each character's own "Cook Meal"
        // sheet button so any participant can trigger the cook as themselves. When omitted,
        // falls back to the classic GM/selected-token flow.
        commandCook = function (msg, content) {
            const charName = content ? content.trim() : "";
            if (!charName && !playerIsGM(msg.playerid)) {
                sendChat("System", `/w "${msg.who}" Only GMs can trigger the cook.`, null, { noarchive: true });
                return;
            }
            if (!state.WuxCookingEvent.active) {
                sendChat("System", `/w GM No cooking event is in progress.`, null, { noarchive: true });
                return;
            }
            const ingredients = state.WuxCookingEvent.ingredients;
            if (Object.keys(ingredients).length === 0) {
                sendChat("System", `/w GM No ingredients have been added.`, null, { noarchive: true });
                return;
            }

            const cookTarget   = charName
                ? TargetReference.GetTargetDataByName(charName)
                : (function () {
                    const targets = TokenReference.GetTokenTargetDataArray(msg);
                    return targets.length > 0 ? targets[0] : null;
                })();
            const cookSkillVar = WuxDef.GetVariable("Skill_Cook");
            const cookCharId   = cookTarget ? cookTarget.charId : null;

            const performCook = function (cookMod, cookName) {
                const roll = new DieRoll();
                roll.rollSkillCheck(0, cookMod);

                const isBland  = roll.total < 9;
                const hasSavor = roll.total >= 12;

                const totalQuantity = Object.values(ingredients).reduce(function (sum, ing) { return sum + ing.quantity; }, 0);
                const feeds = Math.floor(totalQuantity / 5);

                const cookedMealName = isBland ? "Bland Meal" : predictMeal(ingredients);
                const mealLabel      = hasSavor ? `Savoury ${cookedMealName}` : cookedMealName;

                // Deduct ingredients from each character's supplies
                const deductByChar = {};
                Object.keys(ingredients).forEach(function (key) {
                    const ing = ingredients[key];
                    if (!deductByChar[ing.charName]) deductByChar[ing.charName] = {};
                    deductByChar[ing.charName][ing.name] = (deductByChar[ing.charName][ing.name] || 0) + ing.quantity;
                });
                Object.keys(deductByChar).forEach(function (charName) {
                    const chars = findObjs({ _type: "character", name: charName });
                    if (chars.length > 0) {
                        deductGoodsFromCharacter(chars[0].id, deductByChar[charName]);
                    }
                });

                Object.values(state.WuxCookingEvent.tokens).forEach(function (participant) {
                    clearCookingDataForToken(participant);
                });

                state.WuxCookingEvent.active = false;
                state.WuxCookingEvent.initiatorName = "";
                state.WuxCookingEvent.ingredients = {};
                state.WuxCookingEvent.tokens = {};

                const rollDisplay = Format.ShowTooltip(roll.total, roll.message);
                const giveMealCmd = hasSavor
                    ? `[Give Meal](!givemeal ${cookedMealName}|||savoury)`
                    : `[Give Meal](!givemeal ${cookedMealName})`;
                const outputLines = [
                    `${cookName} cooks a meal`,
                    `Cook Check: ${rollDisplay}`,
                    `Created a ${mealLabel} for ${feeds}`,
                    giveMealCmd
                ];

                const messageObject = new SystemInfoMessage(outputLines);
                messageObject.setSender(cookName || "Wuxing");
                WuxMessage.Send(messageObject);
            };

            if (cookCharId) {
                const attributeHandler = new SandboxAttributeHandler(cookCharId);
                attributeHandler.addMod(cookSkillVar);
                attributeHandler.addFinishCallback(function (attrHandler) {
                    const cookMod = attrHandler.parseInt(cookSkillVar, 0, false);
                    performCook(cookMod, cookTarget.displayName);
                });
                attributeHandler.run();
            } else {
                performCook(0, state.WuxCookingEvent.initiatorName);
            }
        },

        handleInput = function (msg, tag, content) {
            switch (tag) {
                case "!adventureoptions":
                    commandAdventureOptions(msg, content);
                    break;
                case "!gather":
                    commandGather(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!gathermaterial": {
                    const parts    = content.split("@@@");
                    const location = parts[0] ? parts[0].trim() : "";
                    const itemName = parts[1] ? parts[1].trim() : "";
                    commandGatherSpecific(msg, TokenReference.GetTokenTargetDataArray(msg), location, itemName);
                    break;
                }
                case "!givemeal":
                    commandGiveMeal(msg, TokenReference.GetTokenTargetDataArray(msg), content);
                    break;
                case "!startcooking":
                    commandStartCooking(msg);
                    break;
                case "!addingredient":
                    commandAddIngredient(msg, content);
                    break;
                case "!removeingredient":
                    commandRemoveIngredient(msg, content);
                    break;
                case "!deleteingredient":
                    commandDeleteIngredient(msg, content);
                    break;
                case "!cook":
                    commandCook(msg, content);
                    break;
                case "!viewcooking":
                    commandViewCooking(msg);
                    break;
                case "!endcooking":
                    commandEndCooking(msg);
                    break;
                case "!viewrecipes":
                    commandViewRecipes(msg);
                    break;
                case "!rest":
                    commandRest(msg);
                    break;
                case "!seematerials":
                    commandSeeMaterials(msg);
                    break;
                case "!hunt":
                    commandHunt(msg);
                    break;
                case "!fish":
                    commandFish(msg);
                    break;
            }
        };

    return {
        CheckInstall: checkInstall,
        HandleInput: handleInput
    };
}());
// ====== Classes
// noinspection JSUnusedGlobalSymbols,JSUnresolvedReference,SpellCheckingInspection,ES6ConvertVarToLetConst

class Dictionary {

    constructor() {
        this.keys = [];
        this.values = {};
        this.dataCreationCallback = {};
    }

    import(data, dataCreationCallback) {
        this.dataCreationCallback = dataCreationCallback;
        if (data != undefined) {
            if (Array.isArray(data)) {
                this.importSheets(data, this.dataCreationCallback);
            } else if (typeof data == "string") {
                this.importStringifiedJson(data, this.dataCreationCallback);
            } else {
                this.importJson(data, this.dataCreationCallback);
            }
        }
    }

    importStringifiedJson(stringifiedJSON, dataCreationCallback) {
        if (stringifiedJSON == undefined || stringifiedJSON == "") {
            return;
        }

        try {
            this.importJson(JSON.parse(stringifiedJSON), dataCreationCallback);
        }
        catch {
            Debug.LogError(`[Dictionary] Unable to parse JSON: ${stringifiedJSON}`);
        }
    }

    importJson(json, dataCreationCallback) {
        if (json == undefined) {
            return;
        }
        this.keys = json.keys;
        if (dataCreationCallback != undefined) {
            this.values = {};
            for (let i = 0; i < json.keys.length; i++) {
                this.values[json.keys[i]] = dataCreationCallback(json.values[json.keys[i]]);
            }
        } else {
            this.values = json.values;
        }
    }

    importSheets(dataArray, dataCreationCallback) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = dataCreationCallback(dataArray[i]);
            if (data != undefined) {
                this.add(data.name, data);
            }
        }
    }

    add(key, value) {
        if (!this.keys.includes(key)) {
            this.keys.push(key);
        }
        this.values[key] = value;
    }
    
    remove(key) {
        if (!this.keys.includes(key)) {
            return;
        }
        this.keys = this.keys.filter(k => k !== key);
        delete this.values[key];
    }

    get(key) {
        return this.values[key];
    }

    getkey(index) {
        return this.keys[index];
    }

    getByIndex(index) {
        return this.get(this.getkey(index));
    }

    set(key, value) {
        this.values[key] = value;
    }

    has(key) {
        return this.keys.includes(key);
    }

    iterate(callback) {
        for (let i = 0; i < this.keys.length; i++) {
            callback(this.values[this.keys[i]], this.keys[i]);
        }
    }

    clean(validKeys) {
        let keys = this.keys.filter(key => validKeys.includes(key));
        let values = {};
        for (let i = 0; i < keys.length; i++) {
            values[keys[i]] = this.values[keys[i]];
        }
        this.keys = keys;
        this.values = values;
    }
    
    clear() {
        this.keys = [];
        this.values = {};
    }
    
    length() {
        return this.keys.length;
    }
}

class DatabaseFilterData {
    constructor(property, value) {
        this.property = property;
        
        if (Array.isArray(value)) {
            this.value = value;
        }
        else {
            this.value = [value];
        }
    }
}

class Database extends Dictionary {
    constructor(data, sortingProperties, dataCreationCallback) {
        super();
        if (sortingProperties != undefined) {
            this.addSortingroperties(sortingProperties);
        }

        this.import(data, dataCreationCallback);
    }

    importJson(json, dataCreationCallback) {
        super.importJson(json, dataCreationCallback);
        this.sortingGroups = json.sortingGroups;
    }

    add(key, value) {
        super.add(key, value);
        this.performAddSortingGroups(value);
    }
    performAddSortingGroups(value) {
        for (let property in this.sortingGroups) {
            if (value != undefined && value.hasOwnProperty(property)) {
                this.addSortingGroup(property, value[property], value);
            }
        }
    }

    addSortingroperties(sortingProperties) {
        this.sortingGroups = {};
        for (let i = 0; i < sortingProperties.length; i++) {
            this.sortingGroups[sortingProperties[i]] = {};
        }
    }

    addSortingGroup(property, propertyValue, newEntry) {
        if (this.sortingGroups != undefined) {
            if (!this.sortingGroups[property].hasOwnProperty(propertyValue)) {
                this.sortingGroups[property][propertyValue] = [];
            }
            this.sortingGroups[property][propertyValue].push(newEntry.name);
        }
    }

    filter(filterData) {
        if (!Array.isArray(filterData)) {
            filterData = [filterData];
        }
        
        let filteredGroup = this.getSortedData(filterData[0]);
        for (let i = 1; i < filterData.length; i++) {
            if (filteredGroup == undefined || filteredGroup.length == 0) {
                return [];
            }
            let nextFilter = this.getSortedData(filterData[i]);
            if (nextFilter != undefined) {
                filteredGroup = filteredGroup.filter(item => nextFilter.includes(item))
            }
        }
        
        if (filteredGroup == undefined || filteredGroup.length == 0) {
            return [];
        }
        return this.getGroupData(filteredGroup);
    }
    
    getSortedData(filterData) {
        let filterOutput = this.getSortedGroup(filterData.property, filterData.value[0]);
        for (let i = 1; i < filterData.value.length; i++) {
            let nextFilter = this.getSortedGroup(filterData.property, filterData.value[i]);
            for (let item of nextFilter) {
                if (!filterOutput.includes(item)) {
                    filterOutput.push(item);
                }
            }
        }
        return filterOutput;
    }

    getSortedGroup(property, propertyValue) {
        if (!this.sortingGroups.hasOwnProperty(property)) {
            let keys = "";
            for (let key in this.sortingGroups) {
                keys += `${key}, `;
            }
            Debug.Log (`Tried to find property ${property} but it does not exist in the database. Valid properties are ${keys}`);
            return [];
        }
        if (!this.sortingGroups[property].hasOwnProperty(propertyValue)) {
            let keys = "";
            for (let key in this.sortingGroups[property]) {
                keys += `${key}, `;
            }
            // Debug.Log (`Tried to find sub property ${propertyValue} but it does not exist in the database. Valid properties are ${keys}`);
            return [];
        }
        let output = this.sortingGroups[property][propertyValue];
        if (output == undefined) {
            return [];
        }
        return output;
    }

    getGroupData(group) {
        let output = [];
        for (let i = 0; i < group.length; i++) {
            output.push(this.get(group[i]));
        }
        return output;
    }

    getPropertyValues(property) {
        let output = [];
        for (let key in this.sortingGroups[property]) {
            output.push(key);
        }
        return output;
    }

    getValuesByProperty(property) {
        let output = [];
        for (let key in this.values) {
            output.push(this.values[key][property]);
        }
        return output;
    }
}

class WuxDataDatabase extends Database {

    constructor(data, dataCreation, filters) {
        if (filters == undefined) {
            filters = ["group"];
        }
        super(data, filters, dataCreation);
    }

    importSheets(dataArray) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = this.dataCreationCallback(dataArray[i]);
            if (this.has(data.name)) {
                this.values[data.name].descriptions.push(data.descriptions[0]);
            } else {
                if (data.group == "") {
                    continue;
                }
                this.add(data.name, data);
            }
        }
    }

    performAddSortingGroups(value) {
        for (let property in this.sortingGroups) {
            if (property == "group") {
                if (value.group.indexOf(";") >= 0) {
                    let groups = value.group.split(";");
                    for (let i = 0; i < groups.length; i++) {
                        if (groups[i].trim() != "") {
                            this.addSortingGroup("group", groups[i].trim(), value);
                        }
                    }
                }
                else {
                    this.addSortingGroup("group", value.group, value);
                }
            }
            else if (value != undefined && value.hasOwnProperty(property)) {
                this.addSortingGroup(property, value[property], value);
            }
        }
    }
}

class ExtendedTechniqueDatabase extends Database {

    constructor(data) {
        let filters = ["style", "group", "affinity", "tier", "action", "skill", "keywords", "rangeType", "damageTypes", "coreDefense"];
        let dataCreation = function (data) {
            return new TechniqueData(data);
        };
        super(data, filters, dataCreation);
    }

    importJson(json) {
        let dataCreationCallback = function (data) {
            return new TechniqueData(data);
        }
        super.importJson(json, dataCreationCallback);
    }

    importSheets(dataArray) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = new TechniqueData(dataArray[i]);
            if (this.has(data.name)) {
                this.get(data.name).importEffectsFromTechnique(data);
            } else {
                if (data.techSet == "") {
                    continue;
                }
                this.add(data.name, data);
            }
        }
    }
    
    performAddSortingGroups(value) {
        for (let property in this.sortingGroups) {
            if (property == "group") {
                if (value.group.indexOf(";") >= 0) {
                    let groups = value.group.split(";");
                    for (let i = 0; i < groups.length; i++) {
                        let tag = groups[i].trim();
                        if (tag != "") {
                            this.addSortingGroup("group", tag, value);
                            // Trait_* tags embedded in the group field (e.g. Social/Support/Utility
                            // keyword traits) are the same concept as forms/impacts/itemTraits keywords
                            // below, just carried on a different field. Index them alongside those so
                            // keyword filters find techniques regardless of which field tagged them.
                            if (tag.indexOf("Trait_") == 0) {
                                this.addSortingGroup("keywords", tag, value);
                            }
                        }
                    }
                }
                else {
                    this.addSortingGroup("group", value.group, value);
                    if (value.group.indexOf("Trait_") == 0) {
                        this.addSortingGroup("keywords", value.group, value);
                    }
                }
            }
            else if (property == "affinity") {
                if (value.affinity.indexOf(";") >= 0) {
                    let groups = value.affinity.split(";");
                    for (let i = 0; i < groups.length; i++) {
                        if (groups[i].trim() != "") {
                            this.addSortingGroup("affinity", groups[i].trim(), value);
                        }
                    }
                }
                else {
                    this.addSortingGroup("affinity", value.affinity, value);
                }
            }
            else if (value != undefined && value.hasOwnProperty(property)) {
                this.addSortingGroup(property, value[property], value);
            }
        }
        let styles = value.techSet.split(";");
        for (let i = 0; i < styles.length; i++) {
            this.addSortingGroup("style", styles[i].trim(), value);
        }
        let forms = value.forms.split(";");
        for (let i = 0; i < forms.length; i++) {
            this.addSortingGroup("keywords", forms[i].trim(), value);
        }
        let impacts = value.impacts.split(";");
        for (let i = 0; i < impacts.length; i++) {
            this.addSortingGroup("keywords", impacts[i].trim(), value);
        }
        let itemTraits = value.itemTraits.split(";");
        for (let i = 0; i < itemTraits.length; i++) {
            this.addSortingGroup("keywords", itemTraits[i].trim(), value);
        }
        for (let i = 0; i < value.damageTypes.length; i++) {
            this.addSortingGroup("damageTypes", value.damageTypes[i].trim(), value);
        }
    }
}

class ExtendedTechniqueStyleDatabase extends Database {

    constructor(data) {
        let filters = ["group", "styleCategory", "mainGroup", "subGroup", "baseStyle"];
        let dataCreation = function (data) {
            return new TechniqueStyle(data);
        };
        super(data, filters, dataCreation);

        this.importStyles(data, dataCreation);
    }
    
    import(data, dataCreationCallback) {
        // overriding the import process
    }
    
    importStyles(data, dataCreationCallback) {
        if (data != undefined) {
            if (Array.isArray(data)) {
                this.importSheets(data, dataCreationCallback);
            } else if (typeof data == "string") {
                this.importStringifiedJson(data, dataCreationCallback);
            } else {
                this.importJson(data, dataCreationCallback);
            }
        }
    }

    importJson(json) {
        let dataCreationCallback = function (data) {
            return new TechniqueStyle(data);
        }
        super.importJson(json, dataCreationCallback);
    }

    importSheets(dataArray) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = new TechniqueStyle(dataArray[i]);
            this.add(data.name, data);
        }
    }

    add(key, value) {
        super.add(key, value);

        let groups = value.group.split(";");
        for (let i = 0; i < groups.length; i++) {
            this.addSortingGroup("styleCategory", groups[i].trim(), value);
        }
    }
}

class ExtendedUsableItemDatabase extends Database {

    constructor(data, dataCreationCallback) {
        let filters = ["group", "category", "bulk", "traits", "commonTechniques", "goodsComponents"];
        super(data, filters, dataCreationCallback);
    }

    importJson(json, dataCreationCallback) {
        super.importJson(json, dataCreationCallback);
    }

    importSheets(dataArray, dataCreationCallback) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = dataCreationCallback(dataArray[i]);
            if (this.has(data.name)) {
                this.get(data.name).technique.importEffectsFromTechnique(data.technique);
            } else {
                this.add(data.name, data);
            }
        }
    }

    performAddSortingGroups(value) {
        for (let property in this.sortingGroups) {
            if (property == "group") {
                if (value.group.indexOf(";") >= 0) {
                    let groups = value.group.split(";");
                    for (let i = 0; i < groups.length; i++) {
                        if (groups[i].trim() != "") {
                            this.addSortingGroup("group", groups[i].trim(), value);
                        }
                    }
                }
                else {
                    this.addSortingGroup("group", value.group, value);
                }
            }
            else if (property == "traits") {
                if (value.traits.indexOf(";") >= 0) {
                    let groups = value.traits.split(";");
                    for (let i = 0; i < groups.length; i++) {
                        if (groups[i].trim() != "") {
                            this.addSortingGroup("traits", groups[i].trim(), value);
                        }
                    }
                }
                else {
                    this.addSortingGroup("traits", value.traits, value);
                }
            }
            else if (property == "goodsComponents") {
                const goodsTypes = value.getGoodsTypes ? value.getGoodsTypes(false) : [];
                for (let i = 0; i < goodsTypes.length; i++) {
                    this.addSortingGroup("goodsComponents", goodsTypes[i], value);
                }
            }
            else if (value != undefined && value.hasOwnProperty(property)) {
                this.addSortingGroup(property, value[property], value);
            }
        }
    }
}

class ExtendedDefinitionDatabase extends Database {
    constructor(data) {
        let dataCreation = function (data) {
            let definition = new DefinitionData(data);
            if (definition.group == "Type") {
                definition.variable += `{0}{1}`;
            }
            return definition;
        };
        super(data, ["group", "subGroup", "mainGroup", "formulaMods", "techMods", "hasMax"], dataCreation);
    }

    importSheets(dataArray, dataCreationCallback) {
        let data = {};
        for (let i = 0; i < dataArray.length; i++) {
            data = dataCreationCallback(dataArray[i]);
            if (data == undefined) {
                continue;
            }
            if (this.has(data.name)) {
                this.values[data.name].descriptions.push(data.descriptions[0]);
            } else {
                this.add(data.name, data);
            }
        }
    }

    add(key, value) {
        super.add(key, value);
        let formulaDefs = value.formula.getDefinitions();
        if (value.subGroup != undefined && value.subGroup.includes(";")) {
            let subGroups = value.subGroup.split(";");
            for (let i = 0; i < subGroups.length; i++) {
                this.addSortingGroup("subGroup", subGroups[i].trim(), value);
            }

        }
        for (let i = 0; i < formulaDefs.length; i++) {
            this.addSortingGroup("formulaMods", formulaDefs[i], value);
        }
        if (value.modifiers.includes(WuxDef._tech)) {
            this.addSortingGroup("techMods", WuxDef._tech, value);
        }
        if (value.modifiers.includes(WuxDef._techset)) {
            this.addSortingGroup("techMods", WuxDef._techset, value);
        }
        if (value.modifiers.includes(WuxDef._gear)) {
            this.addSortingGroup("techMods", WuxDef._gear, value);
        }
        if (value.isResource) {
            this.addSortingGroup("hasMax", "true", value);
        }
    }
}

class TechniqueEffectDatabase extends Database {
    constructor(data) {
        let dataCreation = function (data) {
            return new TechniqueEffect(data);
        };
        super(data, ["type"], dataCreation);
        this.useDefaultWillBreak = false;
    }

    importJson(json) {
        let dataCreationCallback = function (data) {
            return new TechniqueEffect(data);
        }
        super.importJson(json, dataCreationCallback);
    }

    importSheets(dataArray) {
        let dataCreationCallback = function (data) {
            return new TechniqueEffect(data);
        }
        super.importSheets(dataArray, dataCreationCallback);
    }

    getBoostEffects() {
        return this.filter(new DatabaseFilterData("type", "Boost"));
    }

    sanitizeSheetRollAction() {
        let sheetRoll = JSON.stringify(this);
        sheetRoll = sheetRoll.replace(/"/g, "%%");
        sheetRoll = sheetRoll.replace(/:/g, "&&");
        sheetRoll = sheetRoll.replace(/{/g, "<<");
        sheetRoll = sheetRoll.replace(/}/g, ">>");
        sheetRoll = sheetRoll.replace(/%/g, "&#37;");
        sheetRoll = sheetRoll.replace(/\(/g, "&#40;");
        sheetRoll = sheetRoll.replace(/\)/g, "&#41;");
        sheetRoll = sheetRoll.replace(/\*/g, "&#42;");
        sheetRoll = sheetRoll.replace(/\?/g, "&#63;");
        sheetRoll = sheetRoll.replace(/@/g, "&#64;");
        sheetRoll = sheetRoll.replace(/\[/g, "&#91;");
        sheetRoll = sheetRoll.replace(/]/g, "&#93;");
        sheetRoll = sheetRoll.replace(/\(/g, "&#40;");
        sheetRoll = sheetRoll.replace(/\)/g, "&#41;");
        return sheetRoll;
    }

    unsanitizeSheetRollAction(jsonString) {
        jsonString = jsonString.replace(/%%/g, '"');
        jsonString = jsonString.replace(/&&/g, ":");
        jsonString = jsonString.replace(/<</g, "{");
        jsonString = jsonString.replace(/>>/g, "}");
        return JSON.parse(jsonString);
    }

    getDefaultWillbreak() {
        let techniqueEffect = new TechniqueEffect();
        techniqueEffect.defense = "WillBreak";
        techniqueEffect.type = "Status";
        techniqueEffect.subType = "Set";
        techniqueEffect.effect = "Stat_Flustered";
        return techniqueEffect;
    }
}

